-- Schema for Domain: supply | Business: Pharmaceuticals | Version: v1_mvm
-- Generated on: 2026-05-05 21:11:01

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `pharmaceuticals_ecm`.`supply` COMMENT 'Manages end-to-end pharmaceutical supply chain planning and execution including demand forecasting, inventory management, cold-chain logistics, GDP (Good Distribution Practice) compliance, and distribution network management. Covers raw materials, API, excipients, packaging components, and finished goods across manufacturing sites, distribution centers, and third-party logistics providers. Integrates with Kinaxis RapidResponse/Blue Yonder and SAP MM/WM/SD. Tracks SKU, NDC, and lot/batch traceability for both commercial and clinical trial supply chains.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`supply`.`demand_plan` (
    `demand_plan_id` BIGINT COMMENT 'Unique surrogate identifier for the demand plan record in the pharmaceutical supply chain planning system.',
    `access_strategy_id` BIGINT COMMENT 'Foreign key linking to market.access_strategy. Business justification: Demand planning in pharma is directly driven by market access strategy — formulary coverage scope, reimbursement approval dates, and launch sequencing all define the addressable patient population. Su',
    `atc_classification_id` BIGINT COMMENT 'Foreign key linking to masterdata.atc_classification. Business justification: demand_plan.atc_code is a denormalized ATC classification. Linking to masterdata.atc_classification enables therapeutic-area demand aggregation and WHO ATC-based market analysis reports used in pharma',
    `brand_id` BIGINT COMMENT 'Foreign key linking to commercial.brand. Business justification: S&OP consensus demand planning in pharma is brand-driven. The demand plan must reference the brand it forecasts to reconcile commercial revenue targets with supply capacity. A pharma supply planner wo',
    `brand_plan_id` BIGINT COMMENT 'Foreign key linking to commercial.brand_plan. Business justification: The S&OP process explicitly reconciles demand plans against brand plan volume and revenue targets. Linking demand_plan to brand_plan enables consensus forecast approval workflows and plan-vs-actual va',
    `country_id` BIGINT COMMENT 'Foreign key linking to masterdata.country. Business justification: Demand plans are created at country-market level for market access and regulatory forecasting. A pharma demand planner always scopes forecasts by country to align with local regulatory and reimburseme',
    `distribution_network_id` BIGINT COMMENT 'Foreign key linking to supply.distribution_network. Business justification: A demand plan is a statistical/consensus forecast for pharmaceutical SKUs across specific distribution channels and network nodes. demand_plan has distribution_channel (string) but no FK to the distri',
    `exclusivity_period_id` BIGINT COMMENT 'Foreign key linking to intellectual.exclusivity_period. Business justification: Demand forecasts must incorporate exclusivity expiry dates (orphan, pediatric, data exclusivity) as these drive generic entry timing. Critical for commercial forecasting with regulatory exclusivity co',
    `licensing_agreement_id` BIGINT COMMENT 'Foreign key linking to intellectual.licensing_agreement. Business justification: Demand plans for in-licensed products must reference the licensing agreement to apply contractual volume caps, minimum purchase obligations, and territory-specific demand constraints. Royalty calculat',
    `material_id` BIGINT COMMENT 'Reference to the pharmaceutical product (Drug Product/Drug Substance) associated with this demand plan, enabling cross-SKU product-level demand aggregation.',
    `patent_family_id` BIGINT COMMENT 'Foreign key linking to intellectual.patent_family. Business justification: Demand planning for LOE scenarios requires patent family-level analysis (earliest/latest expiry across jurisdictions) to model demand cliffs accurately. A patent family spans multiple countries; plann',
    `patent_id` BIGINT COMMENT 'Foreign key linking to intellectual.patent. Business justification: Demand planning must account for patent expiry dates (LOE events) to forecast generic competition impact on volumes. Critical for commercial forecasting and LOE planning cycles in pharmaceuticals.',
    `plant_id` BIGINT COMMENT 'Reference to the manufacturing or distribution site for which this demand plan is scoped, supporting multi-site supply network planning.',
    `sku_id` BIGINT COMMENT 'Reference to the pharmaceutical SKU (Stock Keeping Unit) for which this demand plan is generated. Covers both commercial and clinical supply SKUs.',
    `unit_of_measure_id` BIGINT COMMENT 'Foreign key linking to masterdata.unit_of_measure. Business justification: demand_plan.uom is a denormalized plain-text UOM. Linking to masterdata.unit_of_measure enforces 3NF and enables consistent UOM conversion in supply planning reports. Pharma planners require validated',
    `adjusted_forecast_qty` DECIMAL(18,2) COMMENT 'Demand quantity after commercial, medical affairs, or supply chain planner adjustments to the statistical baseline. Reflects market intelligence, launch events, tender wins, or clinical trial enrollment changes applied on top of the baseline.',
    `baseline_forecast_qty` DECIMAL(18,2) COMMENT 'Statistically generated baseline demand quantity for the SKU in the forecast period, produced by the statistical forecasting engine (Kinaxis/Blue Yonder) using historical sales, shipment, or consumption data without manual override.',
    `cold_chain_required` BOOLEAN COMMENT 'Indicates whether this SKU requires cold chain (temperature-controlled) logistics and storage throughout the supply chain. Critical for biologics, vaccines, and temperature-sensitive pharmaceutical products. Drives GDP-compliant distribution planning.',
    `consensus_approved_timestamp` TIMESTAMP COMMENT 'Date and time when the demand plan was formally approved through the S&OP consensus process. Marks the transition to frozen/authoritative demand signal for supply execution. Compliant with 21 CFR Part 11 electronic record requirements.',
    `consensus_forecast_qty` DECIMAL(18,2) COMMENT 'Final consensus-approved demand quantity agreed upon during the S&OP/IBP consensus meeting, representing the authoritative demand signal used for supply planning and inventory positioning. Populated only after plan_status reaches consensus_approved.',
    `demand_classification` STRING COMMENT 'Classification of the demand signal by supply chain purpose: commercial (market sales), clinical (investigational product for trials), compassionate use (expanded access programs), sample (promotional/medical samples), or launch (pre-launch inventory build). Drives planning rules and inventory segmentation.. Valid values are `commercial|clinical|compassionate_use|sample|launch`',
    `demand_signal_source` STRING COMMENT 'Origin of the primary demand signal used to generate or adjust this forecast (e.g., Kinaxis RapidResponse statistical engine, Blue Yonder, SAP APO, manual planner input, CRM pipeline, market research, or tender/contract data). [ENUM-REF-CANDIDATE: kinaxis|blue_yonder|sap_apo|manual|crm|market_research|tender — 7 candidates stripped; promote to reference product]',
    `distribution_channel` STRING COMMENT 'The trade channel through which the pharmaceutical product reaches the end customer (e.g., wholesale distributor, direct hospital supply, retail pharmacy, specialty pharmacy, government/tender, export). Influences demand pattern and supply routing. [ENUM-REF-CANDIDATE: wholesale|direct|hospital|retail_pharmacy|specialty_pharmacy|government|export|e_commerce — promote to reference product]',
    `forecast_accuracy_pct` DECIMAL(18,2) COMMENT 'Measured forecast accuracy for the prior equivalent period, expressed as a percentage (0–100). Calculated as 1 minus the Mean Absolute Percentage Error (MAPE) for the SKU-period. Used to assess planning reliability and trigger model recalibration.',
    `forecast_bias` DECIMAL(18,2) COMMENT 'Systematic directional error in the forecast for the prior equivalent period, measured as actual minus forecast quantity. Positive bias indicates under-forecasting; negative bias indicates over-forecasting. Used for continuous improvement of demand planning accuracy.',
    `forecast_granularity` STRING COMMENT 'The time granularity at which the demand forecast quantities are expressed (weekly, monthly, or quarterly buckets). Determines how forecast_period_date is interpreted.. Valid values are `weekly|monthly|quarterly`',
    `forecast_period_date` DATE COMMENT 'The specific time bucket (month, week, or quarter start date) to which the demand quantities in this record apply. Each row represents one SKU-period combination within the planning horizon.',
    `lot_size_qty` DECIMAL(18,2) COMMENT 'Standard manufacturing lot or batch size quantity for the SKU, used to convert demand quantities into production orders and assess capacity requirements. Expressed in the same UOM as forecast quantities.',
    `ndc_code` STRING COMMENT 'FDA National Drug Code (NDC) for the pharmaceutical product/package, used for US market demand planning, regulatory reporting, and supply chain traceability. Format: labeler-product-package (5-4-2).. Valid values are `^[0-9]{5}-[0-9]{4}-[0-9]{2}$`',
    `override_reason_code` STRING COMMENT 'Standardized reason code explaining why the adjusted forecast deviates from the statistical baseline (e.g., new tender win, product launch, competitor entry, clinical trial enrollment change, market withdrawal). Required when adjusted_forecast_qty differs from baseline_forecast_qty. [ENUM-REF-CANDIDATE: tender_win|product_launch|competitor_entry|clinical_enrollment|market_withdrawal|promotional_event|regulatory_change — promote to reference product]',
    `plan_created_timestamp` TIMESTAMP COMMENT 'Timestamp when this demand plan record was first created in the system, providing the audit trail start point for the planning record lifecycle.',
    `plan_last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this demand plan record, supporting audit trail requirements and change management tracking per 21 CFR Part 11 and ICH Q10.',
    `plan_number` STRING COMMENT 'Externally-known business identifier for the demand plan, used for cross-system reference in Kinaxis RapidResponse, Blue Yonder, and SAP S/4HANA. Follows the enterprise demand plan numbering convention.. Valid values are `^DP-[A-Z0-9]{4,20}$`',
    `plan_status` STRING COMMENT 'Current lifecycle status of the demand plan record, tracking progression from initial statistical generation through consensus approval and freeze for supply execution. [ENUM-REF-CANDIDATE: draft|submitted|under_review|consensus_approved|frozen|superseded — promote to reference product if additional statuses are required]. Valid values are `draft|submitted|under_review|consensus_approved|frozen|superseded`',
    `plan_version` STRING COMMENT 'Version identifier of the demand plan, enabling tracking of iterative revisions within a planning cycle (e.g., v1.0, v2.1). Supports version-controlled consensus planning workflows.. Valid values are `^v[0-9]{1,3}.[0-9]{1,3}$`',
    `planner_notes` STRING COMMENT 'Free-text notes entered by the demand planner documenting assumptions, market intelligence, adjustment rationale, or risk factors influencing the forecast. Supports S&OP review and audit trail documentation.',
    `planning_cycle` STRING COMMENT 'The cadence of the demand planning cycle in which this plan was generated (e.g., monthly S&OP cycle, quarterly business review, weekly rolling horizon). Determines the review and approval schedule.. Valid values are `monthly|quarterly|weekly|rolling_13_week`',
    `planning_horizon_end_date` DATE COMMENT 'The last date of the demand planning horizon covered by this plan. Defines the end of the forecast period, typically 12–24 months for pharmaceutical commercial planning.',
    `planning_horizon_start_date` DATE COMMENT 'The first date of the demand planning horizon covered by this plan. Defines the start of the forecast period for supply planning and inventory positioning.',
    `reorder_point_qty` DECIMAL(18,2) COMMENT 'Inventory level at which a replenishment order should be triggered for this SKU, calculated from lead time demand plus safety stock. Used in SAP S/4HANA MRP and Kinaxis supply planning.',
    `safety_stock_qty` DECIMAL(18,2) COMMENT 'Minimum buffer inventory quantity maintained to protect against demand variability and supply disruptions for this SKU in the planning period. Expressed in the same UOM as forecast quantities. Sourced from SAP S/4HANA MM or Kinaxis.',
    `shelf_life_days` STRING COMMENT 'Approved shelf life of the pharmaceutical SKU in days from the date of manufacture. Critical for demand planning to ensure inventory is consumed within expiry, minimizing write-offs and ensuring patient safety compliance.',
    `statistical_model_type` STRING COMMENT 'The statistical forecasting algorithm applied to generate the baseline forecast (e.g., exponential smoothing, ARIMA, Croston, moving average, machine learning ensemble). Sourced from Kinaxis RapidResponse or Blue Yonder model configuration. [ENUM-REF-CANDIDATE: exponential_smoothing|arima|croston|moving_average|holt_winters|ml_ensemble — promote to reference product]',
    `storage_temperature_max_c` DECIMAL(18,2) COMMENT 'Maximum permitted storage temperature in degrees Celsius for this pharmaceutical SKU. Used in conjunction with minimum storage temperature to define the acceptable temperature range for GDP-compliant cold chain management.',
    `storage_temperature_min_c` DECIMAL(18,2) COMMENT 'Minimum required storage temperature in degrees Celsius for this pharmaceutical SKU. Used for cold chain planning, GDP compliance, and distribution network configuration (e.g., -80°C for mRNA vaccines, 2–8°C for biologics).',
    `supply_chain_tier` STRING COMMENT 'Identifies the supply chain tier to which this demand plan applies: Drug Substance (DS/API), Drug Product (DP/FDF), Finished Goods (packaged product), or Packaging Components. Enables multi-tier demand disaggregation from finished goods back to API and raw materials.. Valid values are `drug_substance|drug_product|finished_goods|packaging`',
    `therapeutic_area` STRING COMMENT 'The therapeutic area classification of the pharmaceutical product (e.g., oncology, immunology, rare diseases, cardiovascular, neurology). Used for demand segmentation and portfolio-level planning analytics. [ENUM-REF-CANDIDATE: oncology|immunology|rare_diseases|cardiovascular|neurology|infectious_disease|metabolic — promote to reference product]',
    CONSTRAINT pk_demand_plan PRIMARY KEY(`demand_plan_id`)
) COMMENT 'Statistical and consensus-based demand forecast for pharmaceutical SKUs across commercial and clinical supply chains. Captures baseline forecast, adjusted forecast, consensus-approved quantities, planning horizon, and demand signals from Kinaxis RapidResponse/Blue Yonder. Tracks forecast version, approval status, planning cycle, and demand classification (commercial, clinical, compassionate use). Serves as the authoritative demand signal for supply planning and inventory positioning.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`supply`.`plan` (
    `plan_id` BIGINT COMMENT 'Unique surrogate identifier for the supply plan record in the Databricks Silver Layer. Primary key for this entity.',
    `access_strategy_id` BIGINT COMMENT 'Foreign key linking to market.access_strategy. Business justification: Supply plans are built against market access milestones — planned launch dates, covered markets, and formulary tier targets from the access strategy determine production timing and quantities. S&OP an',
    `brand_id` BIGINT COMMENT 'Foreign key linking to commercial.brand. Business justification: Supply plans are created per brand to meet commercial demand forecasts and launch timelines. Links manufacturing capacity planning to brand lifecycle stage, LOE dates, and promotional spend budgets fo',
    `brand_plan_id` BIGINT COMMENT 'Foreign key linking to commercial.brand_plan. Business justification: Supply plans must be built against a specific brand plan version to ensure production quantities align with commercial revenue and volume targets. S&OP reconciliation and capacity planning reports req',
    `budget_id` BIGINT COMMENT 'Foreign key linking to finance.budget. Business justification: S&OP budget alignment: supply plans drive production and procurement spend that must reconcile with approved budgets during Sales & Operations Planning. Finance validates supply plan quantities and co',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.cost_center. Business justification: Supply plans are linked to cost centers for financial planning, budget allocation, and manufacturing cost tracking. Pharma finance teams require plan-to-cost-center linkage for standard costing and va',
    `demand_plan_id` BIGINT COMMENT 'Reference to the demand plan record that drives this supply plan. Links supply plan to the corresponding demand forecast from the S&OP process, enabling demand-supply reconciliation and gap analysis.',
    `distribution_network_id` BIGINT COMMENT 'Foreign key linking to supply.distribution_network. Business justification: A supply plan (constrained/unconstrained) targets a specific distribution network node for receipt or deployment of drug substance, drug product, or finished goods. plan already has storage_location_i',
    `drug_product_id` BIGINT COMMENT 'Reference to the pharmaceutical product (drug substance, drug product, or FDF) covered by this supply plan. Links to the master product/material record in SAP MM or the product master data product.',
    `exclusivity_period_id` BIGINT COMMENT 'Foreign key linking to intellectual.exclusivity_period. Business justification: Supply planning aligns production with exclusivity periods to optimize inventory before generic competition. Essential for lifecycle supply planning and avoiding excess inventory at exclusivity expiry',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to masterdata.legal_entity. Business justification: Supply plans are owned by a legal entity for intercompany transfer pricing, financial consolidation, and GMP regulatory compliance. Pharma supply planners must attribute plans to the responsible legal',
    `licensing_agreement_id` BIGINT COMMENT 'Foreign key linking to intellectual.licensing_agreement. Business justification: Supply plans for in-licensed or out-licensed products must reference the licensing agreement to enforce supply obligations, minimum batch commitments, territory restrictions, and diligence obligations',
    `packaging_configuration_id` BIGINT COMMENT 'Foreign key linking to product.packaging_configuration. Business justification: Production plans in pharma must specify the packaging configuration to schedule packaging lines, procure primary/secondary materials, and plan serialization capacity. A supply planning expert expects ',
    `patent_family_id` BIGINT COMMENT 'Foreign key linking to intellectual.patent_family. Business justification: Supply plans are built with LOE scenario planning requiring patent family-level analysis — the familys latest expiry date across all jurisdictions determines the true supply planning horizon. Individ',
    `patent_id` BIGINT COMMENT 'Foreign key linking to intellectual.patent. Business justification: Supply plans reference patents to align production capacity with exclusivity periods and avoid overproduction pre-LOE. Essential for capacity planning around patent cliffs and inventory optimization.',
    `site_id` BIGINT COMMENT 'Reference to the manufacturing site (internal or CMO/CDMO) responsible for producing the planned quantity. Links to the site master data record. Supports GDP compliance and site-level capacity planning.',
    `project_id` BIGINT COMMENT 'Foreign key linking to discovery.discovery_project. Business justification: Manufacturing capacity planning and tech transfer activities require visibility to pipeline projects for scale-up planning, site selection, and supply network design. Essential for phase-appropriate s',
    `sku_id` BIGINT COMMENT 'Foreign key linking to product.sku. Business justification: Supply plans in pharma are executed at SKU level for market-specific production scheduling, launch planning, and commercial supply commitments. sku_code is a denormalized plain attribute; FK to sku en',
    `source_site_id` BIGINT COMMENT 'Reference to the originating site for transfer supply type plans. Identifies the site from which material will be transferred to the receiving/destination site. Relevant for inter-site and inter-company supply transfers.',
    `storage_location_id` BIGINT COMMENT 'Reference to the receiving site or distribution center for transfer supply type plans. Identifies where the material will be received after inter-site transfer or CMO/CDMO delivery.',
    `trial_id` BIGINT COMMENT 'Foreign key linking to clinical.trial. Business justification: Supply plans are created for specific clinical trials. A direct trial_id FK on supply.plan enables trial-level supply planning reports, capacity allocation by trial, and S&OP integration where trial s',
    `unit_of_measure_id` BIGINT COMMENT 'Foreign key linking to masterdata.unit_of_measure. Business justification: plan.quantity_uom is a denormalized plain-text UOM. Linking to masterdata.unit_of_measure enforces 3NF and ensures validated UOM master data is used in production planning and regulatory batch records',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the supply plan was formally approved by the authorized supply chain planner or manager. Part of the electronic audit trail required under 21 CFR Part 11 and ICH Q10.',
    `batch_size` DECIMAL(18,2) COMMENT 'Standard or planned batch size for the manufacturing run, expressed in the quantity UOM. Critical for GMP compliance, batch record generation, and capacity utilization calculations. Aligns with the validated batch size in the manufacturing process.',
    `capacity_constraint_flag` BOOLEAN COMMENT 'Indicates whether this supply plan record is constrained by manufacturing capacity limitations (True) or represents an unconstrained theoretical plan (False). Distinguishes constrained from unconstrained plan scenarios.',
    `capacity_utilization_pct` DECIMAL(18,2) COMMENT 'Percentage of available manufacturing capacity consumed by this supply plan at the designated manufacturing site. Used for capacity management, bottleneck identification, and CMO contract utilization tracking.',
    `cold_chain_required` BOOLEAN COMMENT 'Indicates whether the planned material requires cold-chain storage and transportation (True) to maintain product integrity. Triggers cold-chain logistics requirements in GDP-compliant distribution planning.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the supply plan record was first created in the source planning system (Kinaxis RapidResponse, Blue Yonder, or SAP PP). Part of the audit trail for plan lifecycle tracking.',
    `gdp_compliance_flag` BOOLEAN COMMENT 'Indicates whether the supply plan has been reviewed and confirmed as compliant with Good Distribution Practice (GDP) requirements for the planned distribution lanes and storage conditions.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Date and time when the supply plan record was most recently modified in the source planning system. Supports change tracking, plan versioning, and audit trail requirements under 21 CFR Part 11.',
    `lead_time_days` STRING COMMENT 'Total planned lead time in calendar days from production start (or purchase order placement) to material availability at the destination site. Includes manufacturing, QC release, and logistics transit time. Used for MRP scheduling.',
    `material_type` STRING COMMENT 'Classification of the pharmaceutical material covered by this supply plan: Drug Substance (DS), Drug Product (DP), Finished Dosage Form (FDF), Active Pharmaceutical Ingredient (API), excipient, or packaging component. Aligns with CMC categorization.. Valid values are `DS|DP|FDF|API|excipient|packaging`',
    `ndc_code` STRING COMMENT 'National Drug Code assigned by the FDA uniquely identifying the drug product, labeler, and package size. Required for US commercial supply planning and distribution. Applicable to FDF and DP material types.. Valid values are `^[0-9]{4,5}-[0-9]{3,4}-[0-9]{1,2}$`',
    `notes` STRING COMMENT 'Free-text field for supply planners to document assumptions, constraints, risk factors, or exceptions associated with this supply plan record. Supports S&OP decision documentation and audit trail.',
    `number_of_batches` STRING COMMENT 'Total number of manufacturing batches planned within the planning horizon for this supply plan record. Used for capacity loading, CMO scheduling, and GMP batch record planning.',
    `plan_number` STRING COMMENT 'Externally-known business identifier for the supply plan, sourced from Kinaxis RapidResponse, Blue Yonder, or SAP PP (e.g., SP-2024-00123). Used for cross-system traceability and communication with CMOs/CDMOs.',
    `plan_status` STRING COMMENT 'Current lifecycle state of the supply plan. Draft indicates work-in-progress; approved indicates sign-off by supply chain leadership; frozen indicates locked for execution; superseded indicates replaced by a newer version; cancelled indicates plan is void.. Valid values are `draft|approved|frozen|superseded|cancelled`',
    `plan_type` STRING COMMENT 'Classification of the supply plan indicating whether it reflects capacity and material constraints (constrained) or theoretical demand without constraints (unconstrained). Consensus plan represents the agreed S&OP output. [ENUM-REF-CANDIDATE: constrained|unconstrained|consensus|rough_cut|master — promote to reference product]. Valid values are `constrained|unconstrained|consensus|rough_cut|master`',
    `planned_production_qty` DECIMAL(18,2) COMMENT 'Total planned production or procurement quantity for the material within the planning horizon, expressed in the base unit of measure (e.g., kg for DS/API, units for FDF/DP). Core quantitative output of the supply plan.',
    `planned_production_start_date` DATE COMMENT 'The scheduled start date for the manufacturing or procurement activity. Used for capacity planning, CMO scheduling, and lead time management. Derived from planned receipt date minus production lead time.',
    `planned_receipt_date` DATE COMMENT 'The date on which the planned quantity is expected to be received at the destination site or made available in inventory. Used for inventory availability calculations and demand fulfillment scheduling.',
    `planning_cycle` STRING COMMENT 'Identifier for the S&OP or supply planning cycle in which this plan was generated (e.g., 2024-Q3-Cycle2, Monthly-2024-09). Enables tracking of plan evolution across planning cycles and version comparison.',
    `planning_horizon_end_date` DATE COMMENT 'The end date of the planning horizon covered by this supply plan. Defines the latest date for which planned production or receipt quantities are captured. Typically 12–36 months for pharmaceutical supply planning.',
    `planning_horizon_start_date` DATE COMMENT 'The start date of the planning horizon covered by this supply plan. Defines the earliest date for which planned production or receipt quantities are captured. Typically aligned with the S&OP cycle.',
    `reorder_point_qty` DECIMAL(18,2) COMMENT 'Inventory level at which a replenishment order is triggered for the material at the destination site. Used in SAP MM MRP reorder point planning to ensure continuous supply availability.',
    `safety_stock_qty` DECIMAL(18,2) COMMENT 'Planned safety stock quantity for the material at the destination site, expressed in the quantity UOM. Represents the buffer inventory maintained to protect against demand variability and supply disruptions. Configured in SAP MM MRP.',
    `scenario` STRING COMMENT 'Scenario classification for the supply plan, supporting what-if analysis and risk planning. Base is the primary plan; optimistic and pessimistic reflect demand upside/downside; risk_adjusted incorporates supply risk mitigations.. Valid values are `base|optimistic|pessimistic|risk_adjusted`',
    `shelf_life_days` STRING COMMENT 'Remaining shelf life in calendar days for the planned material at the time of planned receipt. Critical for pharmaceutical supply planning to ensure product reaches patients with adequate remaining shelf life per GDP and customer requirements.',
    `storage_condition` STRING COMMENT 'Required storage temperature condition for the planned material (e.g., ambient 15-25°C, refrigerated 2-8°C, frozen -20°C, ultra-frozen -80°C). Drives cold-chain logistics and warehouse configuration requirements.. Valid values are `ambient|refrigerated|frozen|ultra_frozen|controlled_room_temp`',
    `supply_chain_segment` STRING COMMENT 'Indicates whether the supply plan pertains to the commercial supply chain or the clinical trial supply chain. Clinical supply plans are subject to IND/CTA requirements and GCP; commercial plans are subject to GMP and GDP.. Valid values are `commercial|clinical`',
    `supply_type` STRING COMMENT 'Indicates the sourcing strategy for the planned supply: make (internal manufacturing), buy (external procurement from CMO/CDMO), or transfer (inter-site or inter-company stock transfer). Drives MRP logic in SAP PP and Kinaxis.. Valid values are `make|buy|transfer`',
    `version` STRING COMMENT 'Version identifier of the supply plan (e.g., v1.0, v2.3). Supports plan versioning and comparison between constrained and unconstrained scenarios across planning cycles.',
    CONSTRAINT pk_plan PRIMARY KEY(`plan_id`)
) COMMENT 'Constrained and unconstrained supply plan for drug substance (DS), drug product (DP), and finished dosage form (FDF) across manufacturing sites and CMOs/CDMOs. Captures planned production quantities, planned receipt dates, supply source, planning horizon, capacity constraints, and plan version. Integrates with Kinaxis RapidResponse/Blue Yonder and SAP PP. Tracks plan status (draft, approved, frozen) and supply type (make, buy, transfer).';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`supply`.`inventory_lot` (
    `inventory_lot_id` BIGINT COMMENT 'Unique surrogate identifier for each lot/batch-level inventory record in the pharmaceutical supply chain. Primary key for the inventory_lot data product.',
    `brand_id` BIGINT COMMENT 'Foreign key linking to commercial.brand. Business justification: Inventory valuation, expiry management, and revenue recognition in pharma require brand-level aggregation. Enables commercial finance to track inventory by brand for gross-to-net calculations, sample ',
    `drug_master_file_id` BIGINT COMMENT 'Foreign key linking to intellectual.drug_master_file. Business justification: Each inventory lot of an API or drug product is manufactured under a specific DMF. QA lot release and disposition decisions reference the DMF to confirm GMP compliance and manufacturing site authoriza',
    `drug_product_id` BIGINT COMMENT 'Foreign key linking to product.drug_product. Business justification: Inventory lots represent physical stock of specific drug products (formulation+strength+dosage form). Essential for batch traceability, GDP compliance, recall execution, and regulatory lot disposition',
    `investigator_id` BIGINT COMMENT 'Foreign key linking to hcp.investigator. Business justification: GCP drug accountability logs (required by ICH E6 and FDA 21 CFR Part 312) track which investigator received, used, and returned each clinical supply lot. inventory_lot has is_clinical_supply flag but ',
    `material_id` BIGINT COMMENT 'Foreign key linking to masterdata.material. Business justification: Every inventory lot must reference its material master for specifications, regulatory data, storage requirements, quality parameters. Material_number is denormalized identifier; FK enforces referentia',
    `packaging_configuration_id` BIGINT COMMENT 'Foreign key linking to product.packaging_configuration. Business justification: Lots are manufactured in specific packaging configurations. Required for serialization hierarchy (GTIN/NDC mapping), regulatory compliance reporting, and distribution channel planning where package si',
    `patient_access_program_id` BIGINT COMMENT 'Foreign key linking to market.patient_access_program. Business justification: Inventory lots designated for patient access programs (free goods, compassionate use stock) are segregated and tracked separately for program cost accounting, regulatory reporting, and benefit cap man',
    `plan_id` BIGINT COMMENT 'Foreign key linking to supply.plan. Business justification: An inventory lot is created as a result of executing a supply plan (planned production or planned receipt). Linking inventory_lot.plan_id → plan.plan_id connects the physical lot to the supply plan th',
    `plant_id` BIGINT COMMENT 'Foreign key linking to masterdata.plant. Business justification: Inventory lots are held at plants requiring plant master data for GDP authorization, GMP status, capacity management, regulatory inspections. Plant_code is denormalized identifier; FK enforces referen',
    `production_order_id` BIGINT COMMENT 'Foreign key linking to manufacturing.production_order. Business justification: GMP batch traceability and recall management require tracing any inventory lot back to the production order that created it. FDA 21 CFR Part 211 and EU GMP Annex 15 mandate full batch genealogy. No ex',
    `sku_id` BIGINT COMMENT 'Foreign key linking to product.sku. Business justification: Inventory lots in pharma are managed at SKU level for market-specific stock allocation, reimbursement tracking, and serialization compliance. sku_code is a denormalized plain attribute; FK to sku enab',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to masterdata.storage_location. Business justification: Lots are stored at specific storage locations requiring master data for GDP compliance, capacity management, temperature zones, DEA authorization. Storage_location_code is denormalized identifier; FK ',
    `business_partner_id` BIGINT COMMENT 'Foreign key linking to masterdata.business_partner. Business justification: Pharma GMP requires traceability of each inventory lot to its supplier for quality investigations, CAPA management, and supplier qualification audits. inventory_lot.supplier_lot_number implies a suppl',
    `transfer_price_id` BIGINT COMMENT 'Foreign key linking to finance.transfer_price. Business justification: Intercompany inventory valuation: when lots are transferred between legal entities, the approved transfer price governs the intercompany cost applied to that lot. Finance and tax teams reconcile lot u',
    `trial_id` BIGINT COMMENT 'Foreign key linking to clinical.trial. Business justification: Clinical inventory lots (is_clinical_supply=true) are allocated to specific trials. Linking inventory_lot to trial supports IMP accountability reconciliation, expiry management per trial, and regulato',
    `unit_of_measure_id` BIGINT COMMENT 'Foreign key linking to masterdata.unit_of_measure. Business justification: inventory_lot.unit_of_measure is a denormalized plain-text UOM. Linking to masterdata.unit_of_measure enforces 3NF and ensures GMP-compliant UOM validation for batch release and regulatory submissions',
    `capa_reference` STRING COMMENT 'Reference number of the associated Corrective and Preventive Action (CAPA) record in the Quality Management System (QMS) if this lot is subject to an active quality investigation or deviation. Links to MasterControl or TrackWise QMS.',
    `coa_number` STRING COMMENT 'Reference number of the Certificate of Analysis (CoA) issued by the manufacturer or supplier for this lot, confirming that the lot meets all specified quality attributes and release criteria. Required for GMP compliance and regulatory inspections.',
    `cold_chain_break_date` DATE COMMENT 'Date on which a cold chain break or temperature excursion was first detected for this lot. Populated only when temperature_excursion_flag is True. Used to initiate quality impact assessment and determine lot disposition.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the unit_cost valuation (e.g., USD, EUR, GBP). Enables multi-currency inventory valuation reporting across global manufacturing and distribution sites.. Valid values are `^[A-Z]{3}$`',
    `days_until_expiry` STRING COMMENT 'Number of days remaining until the lots expiry date, calculated at the time of data extraction. Used for near-expiry inventory alerts, FEFO prioritization, and supply chain risk management. Negative values indicate expired lots.',
    `dea_schedule` STRING COMMENT 'DEA controlled substance schedule classification (I through V) for this lot, if applicable. Determines the level of security, storage, and record-keeping requirements. Null for non-controlled substances.. Valid values are `I|II|III|IV|V`',
    `expiry_date` DATE COMMENT 'Date after which the lot is no longer suitable for use, as determined by stability studies and approved shelf-life specifications. Critical for FEFO (First Expired First Out) inventory management, GDP compliance, and regulatory reporting. Corresponds to SAP batch expiry date (VFDAT field).',
    `is_clinical_supply` BOOLEAN COMMENT 'Flag indicating whether this lot is designated for use in clinical trials (investigational product supply) rather than commercial distribution. Clinical supply lots are subject to additional regulatory controls under GCP and IND/CTA requirements.',
    `is_controlled_substance` BOOLEAN COMMENT 'Flag indicating whether this lot contains a DEA-scheduled controlled substance requiring additional security, storage, and regulatory reporting obligations under the Controlled Substances Act.',
    `is_gdp_compliant` BOOLEAN COMMENT 'Flag indicating whether this lots storage and handling at the current location is confirmed compliant with Good Distribution Practice (GDP) requirements, including temperature monitoring, security, and documentation standards.',
    `last_movement_date` DATE COMMENT 'Date of the most recent inventory movement (goods receipt, goods issue, transfer posting, or stock transfer) recorded for this lot in SAP. Used for slow-moving inventory analysis and supply chain performance monitoring.',
    `lot_number` STRING COMMENT 'Manufacturer-assigned alphanumeric identifier for the production lot or batch. Enables full lot/batch traceability from raw material receipt through finished goods distribution. Corresponds to SAP batch number (CHARG field). Required for GMP compliance and recall management.',
    `lot_status` STRING COMMENT 'Current quality and disposition status of the lot in the inventory management system. Drives whether the lot is available for use, shipment, or must be held pending quality review. Maps to SAP batch status (unrestricted-use, quality inspection, blocked). [ENUM-REF-CANDIDATE: unrestricted|quality_hold|quarantine|rejected|released|destroyed — promote to reference product]. Valid values are `unrestricted|quality_hold|quarantine|rejected|released|destroyed`',
    `manufacture_date` DATE COMMENT 'Date on which the lot was manufactured or the production process was initiated. Used for shelf-life calculation, lot traceability, and regulatory reporting. Corresponds to SAP batch manufacturing date (HSDAT field).',
    `material_type` STRING COMMENT 'Classification of the material held in this lot. Distinguishes between Active Pharmaceutical Ingredient (API), excipient, packaging component, drug substance (DS), drug product (DP), and finished dosage form (FDF/finished good). Drives storage, handling, and regulatory requirements. [ENUM-REF-CANDIDATE: API|excipient|packaging_component|drug_substance|drug_product|finished_good — promote to reference product]. Valid values are `API|excipient|packaging_component|drug_substance|drug_product|finished_good`',
    `ndc_code` STRING COMMENT 'FDA-assigned National Drug Code in 5-4-2 format uniquely identifying the drug product, including labeler, product, and package codes. Applicable to finished drug products and drug substances registered with the FDA. Null for raw materials and packaging components.. Valid values are `^[0-9]{5}-[0-9]{4}-[0-9]{2}$`',
    `purchase_order_number` STRING COMMENT 'SAP purchase order number associated with the procurement of this lot from an external supplier. Enables financial reconciliation, goods receipt matching, and procurement traceability.',
    `quantity_available` DECIMAL(18,2) COMMENT 'Net quantity of the lot available for new allocations, calculated as quantity_on_hand minus quantity_reserved minus quantity_on_quality_hold. Represents the actionable inventory for supply planning and order fulfillment.',
    `quantity_on_hand` DECIMAL(18,2) COMMENT 'Total physical quantity of the lot currently in stock at the storage location, expressed in the base unit of measure. Represents the gross inventory position before reservations. Sourced from SAP inventory management (MARD/MCHB tables).',
    `quantity_on_quality_hold` DECIMAL(18,2) COMMENT 'Quantity of the lot currently blocked due to quality inspection, Out-of-Specification (OOS) investigation, or quality hold pending Corrective and Preventive Action (CAPA) resolution. Not available for use or shipment.',
    `quantity_reserved` DECIMAL(18,2) COMMENT 'Quantity of the lot that has been reserved for specific production orders, sales orders, or clinical trial supply requests but not yet physically consumed or shipped. Reduces available quantity for new allocations.',
    `receipt_date` DATE COMMENT 'Date on which the lot was received at the current storage location via goods receipt (GR) posting in SAP. Marks the start of the lots residency at the site and triggers incoming quality inspection workflows.',
    `record_created_timestamp` TIMESTAMP COMMENT 'Timestamp when this inventory lot record was first created in the source system (SAP) or the data lakehouse. Supports audit trail requirements under 21 CFR Part 11 and data lineage tracking.',
    `record_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this inventory lot record in the source system or data lakehouse. Supports change data capture (CDC), audit trail requirements under 21 CFR Part 11, and data freshness monitoring.',
    `release_date` DATE COMMENT 'Date on which the lot was formally released by Quality Assurance (QA) for use in manufacturing, clinical supply, or commercial distribution following successful completion of all required quality control testing and review.',
    `retest_date` DATE COMMENT 'Date by which the lot must be retested to confirm continued compliance with specifications before further use or distribution. Applicable primarily to APIs, drug substances, and excipients with defined retest periods per ICH Q7 and approved specifications.',
    `site_code` STRING COMMENT 'Code identifying the manufacturing site, distribution center, or third-party logistics (3PL) location where this lot is physically held. Enables multi-site inventory visibility and GDP compliance tracking.',
    `storage_condition` STRING COMMENT 'Required storage temperature condition for this lot as specified in the products approved labeling and storage requirements. Drives cold-chain logistics planning and GDP compliance. Values: ambient (15–25°C), refrigerated (2–8°C), frozen (-20°C), controlled_room_temp (20–25°C), ultra_low (-60 to -80°C).. Valid values are `ambient|refrigerated|frozen|controlled_room_temp|ultra_low`',
    `supplier_lot_number` STRING COMMENT 'Original lot or batch number assigned by the external supplier, Contract Manufacturing Organization (CMO), or Contract Development and Manufacturing Organization (CDMO). Enables traceability back to the suppliers manufacturing records and Certificate of Analysis (CoA).',
    `temperature_excursion_flag` BOOLEAN COMMENT 'Flag indicating whether this lot has experienced a documented temperature excursion during storage or transit that may impact product quality and requires quality impact assessment per GDP and cold-chain management procedures.',
    `unit_cost` DECIMAL(18,2) COMMENT 'Standard or moving average cost per unit of measure for this lot as recorded in SAP. Used for inventory valuation, COGS calculation, and financial reporting. Classified as confidential due to commercial sensitivity.',
    `valuation_type` STRING COMMENT 'SAP inventory valuation method applied to this lot for financial costing purposes. Determines how the lots value is calculated in the general ledger (standard price, moving average price, or actual cost). Relevant for COGS reporting.. Valid values are `standard|moving_average|actual`',
    CONSTRAINT pk_inventory_lot PRIMARY KEY(`inventory_lot_id`)
) COMMENT 'Lot/batch-level inventory record for raw materials (APIs, excipients), packaging components, drug substance, drug product, and finished goods held at manufacturing sites, distribution centers, and 3PL locations. Captures lot number, NDC, SKU, material number, quantity on hand, quantity reserved, quantity available, storage location, storage condition (ambient, refrigerated, frozen), expiry date, retest date, lot status (unrestricted, quality hold, quarantine, rejected, released), and GDP compliance flags. SSOT for lot-level inventory traceability.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`supply`.`warehouse_receipt` (
    `warehouse_receipt_id` BIGINT COMMENT 'Unique surrogate identifier for the warehouse receipt record in the Databricks Silver Layer. Primary key for this entity.',
    `clinical_supply_order_id` BIGINT COMMENT 'Foreign key linking to supply.clinical_supply_order. Business justification: warehouse_receipt has a clinical_supply_flag boolean indicating clinical supply receipts, but no FK to the clinical_supply_order that triggered the receipt. Adding clinical_supply_order_id normalizes ',
    `distribution_network_id` BIGINT COMMENT 'Foreign key linking to supply.distribution_network. Business justification: Warehouse receipts occur at specific distribution network nodes (plants, warehouses). The plant_code (STRING) should be replaced with distribution_network_id FK to distribution_network.distribution_ne',
    `drug_product_id` BIGINT COMMENT 'Foreign key linking to product.drug_product. Business justification: Goods receipt in pharma requires drug product identification for QP release decisions, storage condition assignment, and GMP-compliant inspection lot creation. A pharma supply chain expert expects war',
    `inventory_lot_id` BIGINT COMMENT 'Foreign key linking to supply.inventory_lot. Business justification: Warehouse receipts create or update inventory lot records upon material receipt. The batch_number (STRING) should be replaced with inventory_lot_id FK to inventory_lot.inventory_lot_id. Material attri',
    `material_id` BIGINT COMMENT 'Foreign key linking to masterdata.material. Business justification: Goods receipt must validate against material master specifications (storage conditions, quality inspection requirements, batch management rules). Critical for GDP compliance, COA verification, and qua',
    `plant_id` BIGINT COMMENT 'Foreign key linking to masterdata.plant. Business justification: Goods receipts occur at specific plants requiring plant master data for GMP certification status, FDA establishment identifier, capacity validation. Essential for receipt authorization, quality inspec',
    `shipment_id` BIGINT COMMENT 'Foreign key linking to supply.shipment. Business justification: A warehouse receipt is the physical confirmation of an inbound shipment arriving at a pharmaceutical manufacturing site, warehouse, or distribution center. Linking warehouse_receipt.shipment_id → ship',
    `stock_transfer_order_id` BIGINT COMMENT 'Foreign key linking to supply.stock_transfer_order. Business justification: A warehouse receipt at the receiving plant is the completion event for a stock transfer order. Linking warehouse_receipt.stock_transfer_order_id → stock_transfer_order.stock_transfer_order_id enables ',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to masterdata.storage_location. Business justification: warehouse_receipt.storage_location is a denormalized plain-text field. Linking to masterdata.storage_location enables GMP-compliant goods receipt posting to validated storage zones and supports GDP co',
    `business_partner_id` BIGINT COMMENT 'Foreign key linking to masterdata.business_partner. Business justification: Warehouse receipts must be traceable to the supplying business partner for GMP supplier qualification, incoming inspection management, and purchase order reconciliation. No supplier FK currently exist',
    `unit_of_measure_id` BIGINT COMMENT 'Foreign key linking to masterdata.unit_of_measure. Business justification: warehouse_receipt.unit_of_measure is a denormalized plain-text UOM. Linking to masterdata.unit_of_measure enforces 3NF and ensures validated UOM master data for GMP goods receipt documentation and reg',
    `actual_receipt_timestamp` TIMESTAMP COMMENT 'The actual date and time the physical materials arrived at the receiving dock or facility. Distinct from the SAP posting date; captures the real-world event time for GDP compliance, cold-chain monitoring, and traceability. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `bill_of_lading_number` STRING COMMENT 'The carriers bill of lading number for the inbound shipment. Provides the legal transport document reference linking the receipt to the logistics carrier record. Used for freight claims, GDP transport documentation, and supply chain traceability.',
    `carrier_name` STRING COMMENT 'The name of the logistics carrier or third-party logistics provider (3PL) responsible for transporting the materials to the receiving site. Used for GDP carrier qualification tracking and freight performance management.',
    `clinical_supply_flag` BOOLEAN COMMENT 'Indicates whether the received material is designated for clinical trial supply (investigational product) rather than commercial supply. True = clinical trial supply subject to IND/GCP requirements; False = commercial supply. Determines applicable regulatory framework and handling procedures.',
    `coa_reference` STRING COMMENT 'The document reference number or identifier for the vendors Certificate of Analysis (CoA) accompanying the shipment. The CoA confirms the material meets specification. Required for GMP compliance and regulatory traceability. Stored in Veeva Vault or LIMS document management.',
    `coc_reference` STRING COMMENT 'The document reference number for the vendors Certificate of Compliance (CoC), confirming the material was manufactured in accordance with GMP and applicable regulatory requirements. Distinct from the CoA which covers analytical test results.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this warehouse receipt record was first created in the source system or data platform. Used for audit trail and data lineage. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `delivery_note_number` STRING COMMENT 'The vendors delivery note or packing slip number accompanying the shipment. Used for physical receipt verification, discrepancy identification, and document archiving per GMP requirements.',
    `gdp_compliance_status` STRING COMMENT 'The GDP compliance check status for this receipt, confirming that the material was transported and received in accordance with Good Distribution Practice guidelines. compliant = all GDP checks passed; non_compliant = one or more GDP deviations identified; pending_review = GDP review in progress.. Valid values are `compliant|non_compliant|pending_review`',
    `gr_document_number` STRING COMMENT 'The SAP Material Document number generated upon posting the goods receipt in SAP S/4HANA MIGO (transaction MIGO/MB01). Serves as the primary business identifier linking this receipt to the source ERP transaction. Format follows SAP material document numbering (e.g., 5000012345).',
    `gr_document_year` STRING COMMENT 'The fiscal year associated with the SAP GR material document number. Required because SAP material document numbers are unique only within a fiscal year. Combined with gr_document_number to form the unique SAP key.',
    `inbound_delivery_number` STRING COMMENT 'SAP inbound delivery document number (transaction VL31N/VL32N) associated with this goods receipt, if applicable. Used when the receipt is triggered by an advance shipping notice (ASN) from the vendor. May be null for direct PO-based receipts.',
    `inspection_lot_number` STRING COMMENT 'The SAP Quality Management (QM) inspection lot number automatically created upon goods receipt posting for materials subject to quality inspection. Links the warehouse receipt to the quality inspection process in SAP QM and LIMS. Null if no inspection is required.',
    `po_line_item` STRING COMMENT 'The specific line item number within the purchase order against which this goods receipt is posted. A single PO may have multiple line items for different materials or delivery schedules.',
    `po_quantity` DECIMAL(18,2) COMMENT 'The ordered quantity as specified in the purchase order line item. Used to calculate receipt variance (received vs. ordered) and to identify over/under deliveries requiring vendor notification or tolerance check.',
    `posting_date` DATE COMMENT 'The accounting posting date of the goods receipt in SAP, determining the fiscal period in which the inventory and accounting entries are recorded. This is the principal business event date for this transaction.',
    `purchase_order_number` STRING COMMENT 'The SAP purchase order number against which this goods receipt is posted. Links the physical receipt to the procurement commitment. Used for three-way matching (PO, GR, invoice) in accounts payable.',
    `quarantine_flag` BOOLEAN COMMENT 'Indicates whether the received material has been placed in quarantine status pending quality inspection or investigation. True = material is quarantined and not available for use; False = material is not in quarantine. Triggers quality inspection workflow in LIMS and QMS.',
    `receipt_status` STRING COMMENT 'Current lifecycle status of the warehouse receipt. posted = GR document successfully posted in SAP; reversed = GR has been reversed/cancelled; blocked = receipt blocked pending resolution; under_inspection = quality inspection in progress; released = inspection complete and stock released for use.. Valid values are `posted|reversed|blocked|under_inspection|released`',
    `received_quantity` DECIMAL(18,2) COMMENT 'The actual quantity of material physically received and counted at the receiving dock, expressed in the base unit of measure. Used for inventory posting, three-way matching, and discrepancy reporting against the PO quantity.',
    `stock_type` STRING COMMENT 'The SAP stock type assigned to the received material upon posting. unrestricted = available for use/sale; quality_inspection = held pending QC inspection (default for GMP materials); blocked = blocked stock due to quality issue or hold; returns = returned goods stock.. Valid values are `unrestricted|quality_inspection|blocked|returns`',
    `storage_condition` STRING COMMENT 'The required storage condition for the received material, determining the appropriate storage area and cold-chain handling requirements. ambient = room temperature; refrigerated = 2–8°C; frozen = -20°C or below; controlled_room_temp = 15–25°C; controlled_substance = DEA-regulated controlled substance requiring secure storage.. Valid values are `ambient|refrigerated|frozen|controlled_room_temp|controlled_substance`',
    `temperature_excursion_flag` BOOLEAN COMMENT 'Indicates whether a temperature excursion was detected during transport or at the time of receipt. True = temperature excursion occurred (requires investigation and potential rejection); False = no temperature excursion detected. Critical for cold-chain materials (biologics, vaccines, temperature-sensitive APIs).',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this warehouse receipt record was last modified in the source system or data platform. Tracks changes to status, inspection results, or corrections. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    CONSTRAINT pk_warehouse_receipt PRIMARY KEY(`warehouse_receipt_id`)
) COMMENT 'Record of physical receipt of materials at a pharmaceutical manufacturing site, warehouse, or distribution center against a purchase order or inbound delivery. Captures GR document number, posting date, material, lot number, received quantity, storage location, vendor, CoA reference, GDP compliance check status, temperature excursion flag, and quarantine status. Aligns with SAP MM goods receipt (MIGO). Triggers quality inspection and lot creation in LIMS.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`supply`.`goods_issue` (
    `goods_issue_id` BIGINT COMMENT 'Unique surrogate primary key for the goods issue record in the Databricks Silver Layer. Serves as the system-generated identifier for each material outbound movement or consumption event.',
    `clinical_supply_order_id` BIGINT COMMENT 'Foreign key linking to supply.clinical_supply_order. Business justification: goods_issue has clinical_trial_number as a free-text string, but clinical supply issuances should be linked to the structured clinical_supply_order record. Adding clinical_supply_order_id → clinical_s',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.cost_center. Business justification: goods_issue.cost_center is a denormalized plain-text field. Linking to masterdata.cost_center enables accurate financial posting of material movements to validated cost centers for manufacturing cost ',
    `delivery_order_id` BIGINT COMMENT 'Foreign key linking to supply.delivery_order. Business justification: Goods issue documents are created as part of delivery order fulfillment. The delivery_document_number (STRING) should be replaced with a proper FK to delivery_order.delivery_order_id. This establishes',
    `distribution_network_id` BIGINT COMMENT 'Foreign key linking to supply.distribution_network. Business justification: Goods issue transactions occur at specific distribution network nodes. The plant_code (STRING) should be replaced with distribution_network_id FK to distribution_network.distribution_network_id. This ',
    `drug_product_id` BIGINT COMMENT 'Foreign key linking to product.drug_product. Business justification: GMP-relevant goods issues in pharma manufacturing must reference the drug product for batch traceability, cost accounting by product, and controlled substance movement reporting. Regulatory audits req',
    `inventory_lot_id` BIGINT COMMENT 'Foreign key linking to supply.inventory_lot. Business justification: Goods issue transactions consume inventory from specific lots. The batch_number (STRING) should be replaced with inventory_lot_id FK to inventory_lot.inventory_lot_id. Material identifiers and descrip',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to masterdata.storage_location. Business justification: goods_issue.issuing_storage_location is a denormalized plain-text field. Linking to masterdata.storage_location enables GMP-compliant goods issue posting from validated storage zones and supports GDP ',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Goods issue automatic accounting: every goods issue (material consumption, intercompany transfer, destruction) generates a journal entry for inventory cost accounting (COGS, write-offs). SAP MM-FI int',
    `material_id` BIGINT COMMENT 'Foreign key linking to masterdata.material. Business justification: Material issuance requires material master data for valuation, specifications, handling instructions, controlled substance schedules. Essential for inventory accounting, GMP compliance, and movement t',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.profit_center. Business justification: goods_issue.profit_center is a denormalized plain-text field. Linking to masterdata.profit_center enables accurate P&L attribution of material movements for segment reporting and intercompany transfer',
    `plant_id` BIGINT COMMENT 'Foreign key linking to masterdata.plant. Business justification: Material issuances to receiving plants require plant master data for GMP status, capacity, regulatory authorization. Receiving_plant is denormalized code; FK enables plant qualification verification a',
    `stock_transfer_order_id` BIGINT COMMENT 'Foreign key linking to supply.stock_transfer_order. Business justification: A goods issue is the sending-side event for a stock transfer order — when materials leave the source plant/warehouse as part of an inter-site transfer. goods_issue has order_reference_number (string) ',
    `unit_of_measure_id` BIGINT COMMENT 'Foreign key linking to masterdata.unit_of_measure. Business justification: goods_issue.unit_of_measure is a denormalized plain-text UOM. Linking to masterdata.unit_of_measure enforces 3NF and ensures validated UOM master data for GMP batch documentation and financial goods m',
    `cold_chain_required` BOOLEAN COMMENT 'Indicates whether the issued material requires cold-chain temperature-controlled handling and transportation (e.g., 2-8°C refrigerated, -20°C frozen, -80°C ultra-cold for biologics and mRNA products). When True, GDP cold-chain documentation including temperature monitoring records must accompany the shipment.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when the goods issue document was first created and posted in SAP (CPUDT + CPUTM in MKPF). Provides the precise audit timestamp for 21 CFR Part 11 electronic records compliance and GMP batch record documentation. Stored in ISO 8601 format with timezone offset.',
    `currency_code` STRING COMMENT 'The three-letter ISO 4217 currency code for the material cost amount (WAERS in SAP). Represents the local currency of the issuing plant. Required for multi-currency financial consolidation and cross-border supply chain cost reporting.. Valid values are `^[A-Z]{3}$`',
    `destruction_certificate_number` STRING COMMENT 'The certificate of destruction document number issued by a licensed waste disposal or pharmaceutical destruction contractor when materials are scrapped or destroyed (movement type 551/552). Required for GMP compliance, DEA controlled substance destruction reporting, and environmental regulatory compliance. Populated only for destruction goods issues.',
    `document_date` DATE COMMENT 'The date the goods issue document was physically created or the actual date of the material movement (BLDAT in SAP). May differ from posting_date when backdated postings occur. Used for audit trail and GMP documentation compliance.',
    `gi_document_number` STRING COMMENT 'The externally-known SAP material document number assigned to the goods issue posting (e.g., 4900012345). This is the primary business identifier referenced in GMP batch records, cost accounting entries, and supply chain traceability. Corresponds to MBLNR in SAP MSEG/MKPF tables.. Valid values are `^[0-9]{10}$`',
    `gi_document_year` STRING COMMENT 'The fiscal year in which the goods issue material document was posted in SAP (MJAHR). Required in combination with gi_document_number to uniquely identify a material document in SAP MM.',
    `gi_status` STRING COMMENT 'Current lifecycle status of the goods issue document. posted indicates the GI is active and inventory has been reduced; reversed indicates a reversal document has been posted (movement type 262/552/602); blocked indicates the document is on quality hold; cancelled indicates the document was voided prior to posting.. Valid values are `posted|reversed|blocked|cancelled`',
    `is_controlled_substance` BOOLEAN COMMENT 'Indicates whether the issued material is a DEA-scheduled controlled substance requiring additional regulatory documentation, DEA Form 222 or CSOS electronic ordering, and controlled substance inventory reconciliation. When True, the goods issue must comply with DEA 21 CFR Part 1304 record-keeping requirements.',
    `is_gmp_relevant` BOOLEAN COMMENT 'Indicates whether this goods issue is subject to Good Manufacturing Practice (GMP) documentation and traceability requirements. True for materials used in GMP-regulated manufacturing, clinical trial supply, or quality testing. False for non-GMP materials such as office supplies, maintenance items, or non-regulated consumables. Drives GMP batch record inclusion and regulatory audit scope.',
    `issued_quantity` DECIMAL(18,2) COMMENT 'The quantity of material issued in the base unit of measure (ERFMG in SAP MSEG). Represents the actual amount consumed, shipped, scrapped, or transferred. Drives inventory reduction, cost accounting entries, and GMP batch record material consumption documentation. Must reconcile with production order component requirements or delivery quantities.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time when the goods issue record was last modified in the source system or Silver Layer. Tracks subsequent changes such as reversal postings, status updates, or data corrections. Required for incremental data pipeline processing and audit trail completeness per 21 CFR Part 11.',
    `material_cost_amount` DECIMAL(18,2) COMMENT 'The total cost value of the goods issue calculated as issued_quantity multiplied by the material valuation price at time of posting (DMBTR in SAP MSEG in local currency). Represents the COGS or cost allocation amount posted to the consuming cost center or production order. Critical for financial reporting, profitability analysis, and manufacturing cost tracking.',
    `movement_type` STRING COMMENT 'SAP MM movement type code that classifies the nature of the goods issue (BWART in MSEG). Drives inventory valuation, account determination, and GMP documentation requirements. Key values: 261=Goods issue to production order (consumption), 551=Scrapping/destruction, 601=Goods issue for delivery/customer shipment, 311=Transfer posting within plant. [ENUM-REF-CANDIDATE: 261|262|551|552|601|602|311|312|901|902 — promote to reference product]',
    `movement_type_description` STRING COMMENT 'Human-readable description of the SAP movement type (e.g., Goods Issue to Production Order, Goods Issue for Delivery, Scrapping, Sample Withdrawal, Transfer Posting). Supports business reporting and GMP batch record documentation without requiring SAP configuration knowledge.',
    `order_reference_number` STRING COMMENT 'The reference number of the consuming or receiving order associated with the goods issue. For production consumption (movement type 261), this is the SAP production order number (AUFNR). For clinical supply, this is the clinical trial supply order number. For customer delivery, this is the SAP sales order number (VBELN). Central to GMP batch record traceability and cost allocation.',
    `order_type` STRING COMMENT 'Classification of the order type associated with the goods issue. Determines the business process context: production_order/process_order for manufacturing consumption, sales_order for commercial customer delivery, clinical_supply_order for investigational product distribution to trial sites, transfer_order for inter-plant movements, destruction_order for controlled substance or expired material disposal.. Valid values are `production_order|process_order|sales_order|clinical_supply_order|transfer_order|destruction_order`',
    `posting_date` DATE COMMENT 'The accounting and inventory posting date of the goods issue (BUDAT in SAP). Determines the period in which inventory reduction and cost accounting entries are recorded. Critical for period-end closing, GMP batch record dating, and regulatory traceability.',
    `reason_code` STRING COMMENT 'The SAP reason code (GRUND) providing additional classification for the goods issue movement, particularly for scrapping, destruction, or non-standard consumption. Examples include: expired material destruction, quality rejection scrap, clinical trial sample, regulatory submission sample, stability testing sample. Supports GMP deviation tracking and regulatory reporting.',
    `receiving_storage_location` STRING COMMENT 'For intra-plant transfer postings (movement type 311), the destination storage location within the same plant. Tracks material movement between warehouse zones, e.g., from quarantine to released stock, from bulk storage to dispensing area, or from cold-chain to ambient staging.',
    `reference_document_number` STRING COMMENT 'External or cross-system reference document number associated with the goods issue (XBLNR in SAP). May reference a purchase order, clinical trial supply request, destruction certificate, quality disposition document, or regulatory sample request. Enables cross-system traceability between SAP and CTMS, LIMS, or QMS systems.',
    `reversal_document_number` STRING COMMENT 'The SAP material document number of the reversal posting (STBLG) if this goods issue has been reversed. A reversal restores inventory and reverses cost accounting entries. Populated only when gi_status = reversed. Required for GMP audit trail and financial period correction documentation.',
    `special_stock_indicator` STRING COMMENT 'SAP special stock indicator (SOBKZ) identifying whether the issued material belongs to a special stock category. Key values: E=Sales order stock (customer-specific), Q=Project stock, K=Consignment stock at customer, W=Vendor consignment stock. Empty value indicates standard own stock. Critical for clinical trial supply (project stock) and consignment management.. Valid values are `E|Q|K|W|`',
    `stock_type` STRING COMMENT 'The quality/availability stock type from which the material was issued (INSMK in SAP). Indicates whether material was issued from unrestricted (released) stock, quality inspection stock, blocked stock, or restricted-use stock. Critical for GMP compliance — goods issues from quality inspection or blocked stock require QA authorization and deviation documentation.. Valid values are `unrestricted|quality_inspection|blocked|restricted`',
    `valuation_type` STRING COMMENT 'The inventory valuation method applied to the goods issue for cost accounting purposes (BWTAR in SAP). Determines how the material consumption cost is calculated: standard cost (standard price from material master), moving average price (MAP), or actual cost. Impacts COGS calculation and financial reporting accuracy.. Valid values are `standard|moving_average|actual`',
    CONSTRAINT pk_goods_issue PRIMARY KEY(`goods_issue_id`)
) COMMENT 'Record of material consumption or outbound movement from inventory including issuance to production orders, clinical trial supply kits, sample distribution, destruction, quality testing, or customer delivery. Captures GI document number, posting date, material, lot number, issued quantity, movement type (production consumption, sales delivery, sample, scrap, transfer posting), cost center or order reference, and issuing storage location. Aligns with SAP MM goods issue (MIGO). Reduces inventory on hand and triggers cost accounting entries. Supports GMP batch record material consumption documentation.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`supply`.`stock_transfer_order` (
    `stock_transfer_order_id` BIGINT COMMENT 'Unique surrogate identifier for the stock transfer order record in the lakehouse silver layer. Primary key for this entity.',
    `drug_product_id` BIGINT COMMENT 'Foreign key linking to product.drug_product. Business justification: STOs plan inter-site transfers of specific drug products for supply network optimization. Product-level link needed for capacity planning, cold chain requirement determination, and controlled substanc',
    `inventory_lot_id` BIGINT COMMENT 'Foreign key linking to supply.inventory_lot. Business justification: Stock transfer orders move specific inventory lots between locations. The batch_number (STRING) should be replaced with inventory_lot_id FK to inventory_lot.inventory_lot_id. Material attributes, expi',
    `material_id` BIGINT COMMENT 'Foreign key linking to masterdata.material. Business justification: Stock transfers require material master for handling instructions, storage conditions, cold chain requirements, DEA schedules. Critical for GDP-compliant transfers, serialization verification, and rec',
    `plan_id` BIGINT COMMENT 'Foreign key linking to supply.plan. Business justification: Stock transfer orders in pharmaceutical supply chains are typically generated from constrained supply plans (e.g., Kinaxis RapidResponse or SAP APO planned orders). Linking stock_transfer_order.plan_i',
    `plant_id` BIGINT COMMENT 'Foreign key linking to masterdata.plant. Business justification: Stock transfers to receiving plants require plant master data for GMP certification, capacity, DEA registration. Receiving_plant_code is denormalized; FK ensures receiving plant qualification, capacit',
    `distribution_network_id` BIGINT COMMENT 'Foreign key linking to supply.distribution_network. Business justification: Stock transfer orders move materials between distribution network nodes. The sending_plant_code (STRING) should be replaced with sending_distribution_network_id FK to distribution_network.distribution',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to masterdata.storage_location. Business justification: stock_transfer_order.sending_storage_location is a denormalized plain-text field. Linking to masterdata.storage_location ensures the sending location is a validated GMP/GDP storage zone, required for ',
    `sku_id` BIGINT COMMENT 'Foreign key linking to product.sku. Business justification: Stock transfer orders in pharma move market-specific SKUs between sites and distribution nodes. SKU-level identification is required for serialization chain-of-custody, market authorization compliance',
    `transfer_price_id` BIGINT COMMENT 'Foreign key linking to finance.transfer_price. Business justification: Intercompany STO pricing: stock transfer orders between legal entities require an approved transfer price for intercompany billing and tax compliance. Finance and supply chain jointly manage STO-to-tr',
    `unit_of_measure_id` BIGINT COMMENT 'Foreign key linking to masterdata.unit_of_measure. Business justification: stock_transfer_order.unit_of_measure is a denormalized plain-text UOM. Linking to masterdata.unit_of_measure enforces 3NF and ensures validated UOM master data for interplant transfer documentation an',
    `cancellation_reason` STRING COMMENT 'Free-text or coded reason for cancellation of the stock transfer order. Populated only when transfer_status is cancelled. Supports root cause analysis and supply chain performance improvement.',
    `carrier_name` STRING COMMENT 'Name of the qualified logistics carrier or 3PL provider responsible for transporting the pharmaceutical materials between locations. Must be a GDP-qualified carrier for pharmaceutical shipments.',
    `cold_chain_required` BOOLEAN COMMENT 'Indicates whether the pharmaceutical material requires cold-chain handling during transport (e.g., refrigerated 2-8°C or frozen -20°C/-80°C conditions). Triggers cold-chain logistics protocols, temperature monitoring requirements, and qualified carrier selection.',
    `controlled_substance_flag` BOOLEAN COMMENT 'Indicates whether the material being transferred is a DEA-scheduled controlled substance. When true, additional regulatory controls apply including DEA Form 222 or CSOS electronic ordering, chain of custody documentation, and secure transport requirements.',
    `dea_schedule` STRING COMMENT 'Drug Enforcement Administration (DEA) schedule classification for controlled substances (I through V). Null for non-controlled materials. Determines the level of regulatory control and documentation required for the transfer.. Valid values are `I|II|III|IV|V`',
    `delivery_document_number` STRING COMMENT 'SAP outbound delivery document number (transaction VL10) created from the stock transfer order for goods issue processing. Links the STO to the physical shipment execution in SAP WM/SD.. Valid values are `^[0-9]{10}$`',
    `gdp_compliant` BOOLEAN COMMENT 'Indicates whether the stock transfer order has been executed in full compliance with Good Distribution Practice (GDP) requirements, including qualified carrier use, temperature monitoring, chain of custody documentation, and deviation management.',
    `goods_issue_date` DATE COMMENT 'Actual date on which goods issue was posted at the sending plant, marking the departure of materials from the source location. Triggers inventory reduction at the sending plant and initiates in-transit stock.',
    `goods_receipt_date` DATE COMMENT 'Actual date on which goods receipt was posted at the receiving plant, confirming arrival and acceptance of the transferred materials. Triggers inventory increase at the receiving plant and closes the in-transit stock.',
    `issued_quantity` DECIMAL(18,2) COMMENT 'Actual quantity of material for which goods issue (GI) has been posted at the sending plant. May differ from transfer_quantity in cases of partial goods issue. Corresponds to SAP movement type 351/641 posted quantity.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Date and time when the stock transfer order record was last modified in the source system. Used for change tracking, audit trail, and incremental data loading in the lakehouse.',
    `movement_type` STRING COMMENT 'SAP inventory management movement type code used for the stock transfer. Key values: 301 (one-step plant-to-plant), 303/305 (two-step transfer order), 351 (goods issue for STO), 641/647 (goods issue with delivery). Determines accounting and inventory impact.. Valid values are `301|303|305|351|641|647`',
    `priority_level` STRING COMMENT 'Business priority assigned to the stock transfer order. Critical transfers may relate to patient safety supply continuity, clinical trial supply, or shortage situations. Drives scheduling and resource allocation in supply chain planning.. Valid values are `routine|urgent|critical`',
    `reason_code` STRING COMMENT 'Business reason code explaining why the stock transfer was initiated. Examples include demand replenishment, safety stock replenishment, inter-company transfer, clinical trial supply, product recall, quality hold relocation, or returns processing. [ENUM-REF-CANDIDATE: demand_replenishment|safety_stock|inter_company|clinical_supply|recall|quality_relocation|returns|balance_stock — promote to reference product]',
    `received_quantity` DECIMAL(18,2) COMMENT 'Actual quantity of material for which goods receipt (GR) has been posted at the receiving plant. May differ from issued_quantity due to transit losses, damage, or rejection. Corresponds to SAP movement type 101/105 posted quantity.',
    `receiving_storage_location` STRING COMMENT 'SAP storage location code within the receiving plant where the materials will be placed upon goods receipt. Identifies the specific warehouse area, cold-room, quarantine zone, or controlled substance vault at the destination site.. Valid values are `^[A-Z0-9]{1,10}$`',
    `requested_delivery_date` DATE COMMENT 'The date by which the receiving plant requires the materials to arrive. Used for supply chain planning, scheduling goods issue, and measuring on-time delivery performance. Corresponds to the SAP STO delivery date field.',
    `shipping_condition` STRING COMMENT 'Shipping service level or condition required for the transfer. Determines carrier selection, transit time expectations, and special handling requirements. Corresponds to SAP SD shipping condition configuration.. Valid values are `standard|express|overnight|temperature_controlled|hazmat`',
    `sto_creation_timestamp` TIMESTAMP COMMENT 'Date and time when the stock transfer order was created in the source system (SAP MM). Represents the business event timestamp of order initiation. Used for lead time analysis and supply chain performance reporting.',
    `sto_number` STRING COMMENT 'Externally-known business document number assigned by SAP MM for the inter-plant or inter-site stock transfer order. Corresponds to the SAP Purchase Order number used for STO processing (document type UB or NB).. Valid values are `^[A-Z0-9-]{1,20}$`',
    `stock_type` STRING COMMENT 'SAP stock type of the material at the sending location prior to transfer. Indicates whether the material is in unrestricted use, quality inspection (QI) stock, blocked stock, or restricted-use stock. Impacts GDP compliance and release status.. Valid values are `unrestricted|quality_inspection|blocked|restricted`',
    `storage_condition` STRING COMMENT 'Required storage and transport temperature condition for the pharmaceutical material. Drives cold-chain logistics planning and carrier qualification. Values: ambient (15-25°C), refrigerated (2-8°C), frozen (-20°C), deep_frozen (-80°C), controlled_room_temp (20-25°C).. Valid values are `ambient|refrigerated|frozen|deep_frozen|controlled_room_temp`',
    `supply_chain_type` STRING COMMENT 'Distinguishes whether the stock transfer is part of the commercial supply chain or the clinical trial supply chain. Clinical trial transfers require additional traceability and compliance controls per GCP and IND/CTA requirements.. Valid values are `commercial|clinical_trial`',
    `tracking_number` STRING COMMENT 'Carrier-assigned tracking number or waybill number for the shipment associated with this stock transfer order. Enables real-time shipment visibility and chain of custody documentation for GDP compliance.',
    `transfer_category` STRING COMMENT 'Classifies the nature of the transfer based on the sending and receiving location types: plant-to-plant, distribution center to plant, plant to distribution center, DC-to-DC, or involving a third-party logistics (3PL) provider. Supports network-level supply chain analytics.. Valid values are `plant_to_plant|dc_to_plant|plant_to_dc|dc_to_dc|plant_to_3pl|3pl_to_plant`',
    `transfer_quantity` DECIMAL(18,2) COMMENT 'Quantity of the pharmaceutical material ordered for transfer in the base unit of measure. Represents the planned transfer quantity as specified in the STO line item.',
    `transfer_status` STRING COMMENT 'Current lifecycle status of the stock transfer order. Tracks progression from creation through goods issue, in-transit, goods receipt, and closure or cancellation. [ENUM-REF-CANDIDATE: draft|open|goods_issued|in_transit|partially_received|received|cancelled|blocked — promote to reference product]. Valid values are `draft|open|in_transit|partially_received|received|cancelled`',
    `transfer_type` STRING COMMENT 'Indicates whether the transfer is a one-step transfer (goods issue and receipt posted simultaneously) or a two-step transfer (goods issue posted at sending plant, goods receipt posted separately at receiving plant). Aligns with SAP MM movement types 301/303/305.. Valid values are `one_step|two_step`',
    CONSTRAINT pk_stock_transfer_order PRIMARY KEY(`stock_transfer_order_id`)
) COMMENT 'Inter-site or inter-plant stock transfer order for pharmaceutical materials between manufacturing sites, distribution centers, and 3PL locations. Captures transfer order number, sending plant/storage location, receiving plant/storage location, material, lot number, transfer quantity, transfer type (one-step, two-step), GDP compliance requirements, cold-chain requirements, and transfer status. Aligns with SAP MM/WM stock transfer order management.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`supply`.`shipment` (
    `shipment_id` BIGINT COMMENT 'Unique surrogate identifier for the shipment record in the Silver Layer lakehouse. Primary key for the supply.shipment data product.',
    `business_partner_id` BIGINT COMMENT 'Reference to the logistics carrier or freight forwarder responsible for transporting this shipment. Maps to SAP SD forwarding agent (TDLNR).',
    `clinical_supply_order_id` BIGINT COMMENT 'Foreign key linking to supply.clinical_supply_order. Business justification: Shipments can fulfill clinical supply orders. This FK links shipments to the clinical orders they fulfill. No columns to remove as shipment doesnt currently have denormalized clinical order attribute',
    `delivery_order_id` BIGINT COMMENT 'Reference to the outbound or inbound delivery document associated with this shipment. Maps to SAP SD Delivery (LIKP/LIPS) or SAP MM Stock Transfer Order delivery.',
    `country_id` BIGINT COMMENT 'Foreign key linking to masterdata.country. Business justification: shipment.destination_country_code is a denormalized plain-text field. Linking to masterdata.country enables import permit validation, serialization requirement checks (DSCSA/EU FMD), and customs compl',
    `drug_product_id` BIGINT COMMENT 'Foreign key linking to product.drug_product. Business justification: Pharma shipments require drug product traceability for GDP compliance, DSCSA/FMD serialization verification, and import/export regulatory declarations. Shipments can exist without delivery orders (e.g',
    `investigational_site_id` BIGINT COMMENT 'Foreign key linking to clinical.investigational_site. Business justification: IMP shipments are delivered to specific investigational sites. Linking shipment to investigational_site enables GDP delivery confirmation per site, supports site-level IMP inventory reconciliation, an',
    `material_id` BIGINT COMMENT 'Foreign key linking to masterdata.material. Business justification: Shipping requires material specifications for packaging, handling, regulatory compliance (hazmat, controlled substances), temperature requirements. Essential for carrier selection, customs documentati',
    `distribution_network_id` BIGINT COMMENT 'Foreign key linking to supply.distribution_network. Business justification: Shipments originate from distribution network nodes (plants, warehouses, DCs). The origin_location_code (STRING) should be replaced with origin_distribution_network_id FK to distribution_network.distr',
    `patient_access_program_id` BIGINT COMMENT 'Foreign key linking to market.patient_access_program. Business justification: Shipments fulfilling compassionate use, expanded access, or free-goods patient access programs must be traceable to the program for cost accounting, regulatory reporting, and program budget reconcilia',
    `patient_id` BIGINT COMMENT 'Foreign key linking to patient.patient. Business justification: Decentralized clinical trials ship investigational products directly to patients homes. Logistics systems must track destination patient for delivery coordination, temperature monitoring accountabili',
    `payer_account_id` BIGINT COMMENT 'Foreign key linking to market.payer_account. Business justification: Shipments to specialty pharmacies, PBMs, and direct payer channels must be tracked by payer account for contract compliance verification, chargeback reconciliation, and rebate claim validation. Essent',
    `sku_id` BIGINT COMMENT 'Foreign key linking to product.sku. Business justification: Shipments in pharma are executed at SKU level for market-specific regulatory compliance (country-specific NDC, reimbursement codes). Direct clinical supply shipments may not have a delivery order, req',
    `stock_transfer_order_id` BIGINT COMMENT 'Reference to the Stock Transfer Order (STO) when this shipment represents an inter-site transfer. Applicable for both one-step and two-step STO processing in SAP MM. Null for customer-facing outbound deliveries.',
    `trial_id` BIGINT COMMENT 'Foreign key linking to clinical.trial. Business justification: All IMP shipments are made under a specific trial. Linking shipment to trial enables supply operations to report total shipment activity per trial for IND annual reports, clinical supply cost reconcil',
    `unit_of_measure_id` BIGINT COMMENT 'Foreign key linking to masterdata.unit_of_measure. Business justification: shipment.quantity_uom is a denormalized plain-text UOM. Linking to masterdata.unit_of_measure enforces 3NF and ensures validated UOM master data for customs declarations and GDP-compliant shipment doc',
    `actual_delivery_date` DATE COMMENT 'Confirmed date the goods were received and accepted at the destination. Populated upon proof-of-delivery (POD) confirmation. Used for on-time delivery performance measurement and GDP compliance documentation.',
    `cold_chain_required` BOOLEAN COMMENT 'Indicates whether this shipment requires temperature-controlled cold-chain logistics. True for biologics, vaccines, insulin, and other temperature-sensitive pharmaceutical products. Triggers mandatory temperature monitoring and GDP cold-chain documentation requirements.',
    `controlled_substance_flag` BOOLEAN COMMENT 'Indicates whether the shipment contains DEA-scheduled controlled substances (e.g., opioids, Schedule II-V narcotics). Triggers DEA Form 222 or CSOS electronic order requirements and enhanced chain-of-custody documentation.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the shipment record was first created in the source system (SAP SD/MM). Audit trail field for data lineage and compliance. Corresponds to SAP ERDAT/ERZET fields.',
    `customs_declaration_number` STRING COMMENT 'Official customs entry or export declaration number assigned by the customs authority for cross-border shipments. Required for import/export compliance tracking and regulatory audit trails. Null for domestic shipments.',
    `customs_required` BOOLEAN COMMENT 'Indicates whether this shipment crosses international borders and requires customs import/export documentation (commercial invoice, packing list, import license, health certificate). True for cross-border shipments.',
    `destination_location_code` STRING COMMENT 'Business identifier (SAP Plant code, DC code, customer account, or clinical site number) of the destination receiving the shipment. Used for delivery confirmation and traceability.',
    `destination_location_type` STRING COMMENT 'Classifies the type of destination receiving the shipment. Drives GDP compliance requirements, cold-chain monitoring thresholds, and customs documentation needs. [ENUM-REF-CANDIDATE: plant|distribution_center|3pl_warehouse|distributor|wholesaler|hospital|pharmacy|clinical_trial_site — promote to reference product]',
    `estimated_delivery_date` DATE COMMENT 'Planned or carrier-confirmed estimated date of arrival at the destination. Used for supply chain planning, cold-chain monitoring window calculations, and customer service commitments. Corresponds to SAP planned delivery date (LFDAT).',
    `gdp_compliance_status` STRING COMMENT 'GDP compliance assessment status for this shipment. compliant = no deviations detected; deviation_open = temperature excursion or handling deviation under investigation; deviation_closed = deviation resolved with CAPA; pending_review = awaiting QA assessment of monitoring data.. Valid values are `compliant|deviation_open|deviation_closed|pending_review`',
    `gross_weight_kg` DECIMAL(18,2) COMMENT 'Total gross weight of the shipment in kilograms, including packaging and pallets. Required for carrier freight billing, dangerous goods declarations (IATA/IMDG), and customs documentation.',
    `hazardous_goods_flag` BOOLEAN COMMENT 'Indicates whether the shipment contains dangerous goods (e.g., flammable solvents, cytotoxic agents, radioactive materials) subject to IATA Dangerous Goods Regulations (DGR) or IMDG Code. Triggers mandatory DG documentation and packaging requirements.',
    `incoterms_code` STRING COMMENT 'International Commercial Terms (Incoterms 2020) defining the transfer of risk and responsibility between shipper and consignee. Determines who bears cost and risk during transit. Corresponds to SAP SD Incoterms (INCO1). Critical for customs valuation and insurance. [ENUM-REF-CANDIDATE: EXW|FCA|CPT|CIP|DAP|DPU|DDP|FAS|FOB|CFR|CIF — 11 candidates stripped; promote to reference product]',
    `incoterms_location` STRING COMMENT 'Named place or port associated with the Incoterms code, specifying the exact point of risk/cost transfer (e.g., Rotterdam for FOB Rotterdam). Corresponds to SAP SD Incoterms Part 2 (INCO2).',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the shipment record. Used for incremental data loading, change detection, and audit trail compliance. Corresponds to SAP AEDAT/AEZET fields.',
    `lot_number` STRING COMMENT 'Manufacturing lot or batch number of the pharmaceutical goods being shipped. Critical for GMP traceability, recall management, and CoA linkage. Corresponds to SAP batch number (CHARG). Enables end-to-end lot traceability from manufacturing to patient.',
    `origin_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the country from which the shipment originates. Used for customs documentation, import/export compliance, and GDP lane qualification.. Valid values are `^[A-Z]{3}$`',
    `origin_location_type` STRING COMMENT 'Classifies the type of origin location from which the shipment departs. Supports routing logic and GDP compliance tracking across the pharmaceutical distribution network.. Valid values are `plant|distribution_center|3pl_warehouse|cmo_site|clinical_depot`',
    `pro_number` STRING COMMENT 'Carrier-assigned Progressive (PRO) number or airway bill number (AWB) / bill of lading (BOL) number used to track the shipment within the carriers system. Primary reference for carrier communication and proof-of-delivery retrieval.',
    `serialization_verified` BOOLEAN COMMENT 'Indicates whether the drug product serialization data (2D DataMatrix barcodes at unit/case level) has been verified and reported to the applicable track-and-trace system (DSCSA in US, FMD in EU) prior to shipment. Required for commercial pharmaceutical distribution.',
    `shipment_date` DATE COMMENT 'Actual date the goods were physically dispatched from the origin location. The principal business event date for this transaction. Corresponds to SAP goods issue posting date (WADAT_IST). Used for GDP compliance, shelf-life calculations, and delivery performance KPIs.',
    `shipment_number` STRING COMMENT 'Externally-known business identifier for the shipment, sourced from SAP SD (transaction VT01N/VT02N). Used for cross-system traceability and carrier communication. Corresponds to SAP Shipment Number (TKNUM).',
    `shipment_status` STRING COMMENT 'Current lifecycle status of the shipment. planned = shipment created but not yet dispatched; in_transit = goods picked up by carrier; delivered = confirmed receipt at destination; cancelled = shipment voided; on_hold = blocked pending resolution (e.g., GDP deviation, customs hold); returned = goods returned to origin.. Valid values are `planned|in_transit|delivered|cancelled|on_hold|returned`',
    `shipped_quantity` DECIMAL(18,2) COMMENT 'Quantity of goods dispatched in this shipment, expressed in the base unit of measure (UoM). For finished goods, typically in units (EA) or cases. For API/DS, typically in kg. Must reconcile with delivery document quantity.',
    `temperature_max_c` DECIMAL(18,2) COMMENT 'Maximum acceptable storage and transit temperature in degrees Celsius for this shipment. Defined by the drug products approved storage conditions (e.g., 8°C for refrigerated, 25°C for controlled room temperature). Exceedances trigger GDP deviation investigations.',
    `temperature_min_c` DECIMAL(18,2) COMMENT 'Minimum acceptable storage and transit temperature in degrees Celsius for this shipment. Defined by the drug products approved storage conditions (e.g., 2°C for refrigerated products, -20°C for frozen biologics). Used to configure temperature monitoring device alarms.',
    `temperature_monitor_device_code` STRING COMMENT 'Unique identifier of the temperature data logger or monitoring device (e.g., Sensitech TempTale, Berlinger ELPRO) placed within the shipment packaging. Used to retrieve temperature excursion data post-delivery for GDP compliance review.',
    `transfer_type` STRING COMMENT 'Classifies the nature of the goods movement. outbound_customer = commercial delivery to distributor/wholesaler/hospital/pharmacy; inter_site_one_step = direct stock transfer between plants; inter_site_two_step = STO with intermediate goods receipt; 3pl_transfer = movement to/from third-party logistics provider; returns = reverse logistics; clinical_trial_supply = IMP shipment to clinical trial site. [ENUM-REF-CANDIDATE: outbound_customer|inter_site_one_step|inter_site_two_step|3pl_transfer|returns|clinical_trial_supply — promote to reference product]. Valid values are `outbound_customer|inter_site_one_step|inter_site_two_step|3pl_transfer|returns|clinical_trial_supply`',
    `transport_mode` STRING COMMENT 'Primary mode of transport used for this shipment. Drives cold-chain packaging requirements, transit time expectations, and customs documentation. air = air freight; road = truck/van; sea = ocean freight; rail = rail freight; courier = express parcel; multimodal = combination of modes.. Valid values are `air|road|sea|rail|courier|multimodal`',
    `un_number` STRING COMMENT 'United Nations (UN) four-digit number identifying the hazardous substance or article being shipped (e.g., UN3373 for Biological Substance Category B, UN1170 for ethanol). Required on dangerous goods declarations when hazardous_goods_flag is True.. Valid values are `^UN[0-9]{4}$`',
    `volume_m3` DECIMAL(18,2) COMMENT 'Total volumetric measurement of the shipment in cubic metres. Used for freight cost calculation (chargeable weight), container/truck capacity planning, and cold-chain packaging validation.',
    CONSTRAINT pk_shipment PRIMARY KEY(`shipment_id`)
) COMMENT 'Physical movement record and SSOT for all pharmaceutical goods movements including outbound customer deliveries, inter-site stock transfers (one-step and two-step), 3PL movements, and returns. Captures shipment number, origin and destination (plant, DC, 3PL, distributor, wholesaler, hospital, pharmacy, clinical trial site), carrier, mode of transport, transfer type, NDC, lot numbers, shipped quantity, shipment date, estimated/actual delivery date, incoterms, cold-chain requirements (temperature range, monitoring device ID), GDP compliance status, customs/import documentation, and stock transfer processing status. Subsumes stock transfer order functionality — inter-site transfers are modeled as shipments with transfer_type indicating one-step or two-step processing. Aligns with SAP SD shipment management and SAP MM stock transfer processing.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`supply`.`delivery_order` (
    `delivery_order_id` BIGINT COMMENT 'Unique surrogate identifier for the outbound delivery order record in the pharmaceutical supply chain lakehouse (Silver Layer). Primary key for this entity.',
    `business_partner_id` BIGINT COMMENT 'Reference to the ship-to party (customer, distribution center, hospital, pharmacy, or clinical site) that is the physical destination of this delivery.',
    `contract_account_id` BIGINT COMMENT 'Foreign key linking to commercial.contract_account. Business justification: Supply delivery orders should link to commercial contract accounts for customer shipments and order fulfillment. This enables integrated order-to-cash process and customer account management across co',
    `distribution_network_id` BIGINT COMMENT 'Foreign key linking to supply.distribution_network. Business justification: A delivery order is fulfilled from a specific distribution network node (warehouse or DC). No FK currently links delivery_order to distribution_network. Adding distribution_network_id → distribution_n',
    `drug_product_id` BIGINT COMMENT 'Foreign key linking to product.drug_product. Business justification: GDP-compliant delivery order processing requires direct drug product identification for controlled substance scheduling, FEFO compliance, and cold chain verification. A pharma logistics expert would e',
    `inventory_lot_id` BIGINT COMMENT 'Foreign key linking to supply.inventory_lot. Business justification: Delivery orders are fulfilled from specific inventory lots. The batch_number (STRING) should be replaced with inventory_lot_id FK to inventory_lot.inventory_lot_id. Material identifiers, SKU, and expi',
    `material_id` BIGINT COMMENT 'Reference to the pharmaceutical material (finished drug product, API, or packaging component) being delivered. Corresponds to SAP Material Master (MM60).',
    `patient_access_program_id` BIGINT COMMENT 'Foreign key linking to market.patient_access_program. Business justification: Specialty pharmacy and free-goods delivery orders are fulfilled under patient access programs. Program cost accounting, compliance reporting, and benefit cap tracking require linking each delivery ord',
    `plan_id` BIGINT COMMENT 'Foreign key linking to supply.plan. Business justification: A delivery order is the fulfillment execution document for a supply plan. Linking delivery_order.plan_id → plan.plan_id connects the outbound delivery to the supply plan that drove it, enabling plan-v',
    `sku_id` BIGINT COMMENT 'Foreign key linking to product.sku. Business justification: Delivery orders in pharma are fulfilled at SKU level (market-specific pack, strength, country). sku_code is a denormalized plain attribute; replacing with FK to sku enables market-specific stock alloc',
    `storage_location_id` BIGINT COMMENT 'Reference to the warehouse or storage location from which goods are issued. Corresponds to SAP WM storage location.',
    `unit_of_measure_id` BIGINT COMMENT 'Foreign key linking to masterdata.unit_of_measure. Business justification: delivery_order.unit_of_measure is a denormalized plain-text UOM. Linking to masterdata.unit_of_measure enforces 3NF and ensures validated UOM master data for delivery documentation, FEFO compliance, a',
    `actual_goods_issue_date` DATE COMMENT 'The actual date on which goods issue was posted in SAP, representing the physical departure of pharmaceutical goods from the warehouse. Critical for lot traceability and GDP compliance.',
    `clinical_supply_flag` BOOLEAN COMMENT 'Indicates whether this delivery is for clinical trial investigational product (IP) supply rather than commercial distribution. Clinical supply deliveries require additional chain-of-custody and IND compliance documentation.',
    `cold_chain_required` BOOLEAN COMMENT 'Indicates whether this delivery requires temperature-controlled cold-chain logistics (refrigerated or frozen transport). Triggers cold-chain carrier assignment and temperature monitoring requirements.',
    `controlled_substance_schedule` STRING COMMENT 'DEA schedule classification (I–V) for controlled substance pharmaceutical products in this delivery. Required for DEA 222 form compliance and controlled substance chain-of-custody tracking. not_applicable for non-controlled products.. Valid values are `I|II|III|IV|V|not_applicable`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the delivery order record was first created in the source system (SAP SD). Used for audit trail and data lineage in the Silver Layer lakehouse.',
    `delivery_number` STRING COMMENT 'Externally-known SAP outbound delivery document number (e.g., 80XXXXXXXX) generated by SAP SD VL01N. Used as the primary business reference across warehouse, logistics, and customer-facing communications.',
    `delivery_priority` STRING COMMENT 'Priority classification for warehouse and logistics execution of this delivery. Emergency and clinical priorities trigger expedited picking, packing, and carrier assignment for patient safety or clinical trial continuity.. Valid values are `standard|urgent|emergency|clinical`',
    `delivery_quantity` DECIMAL(18,2) COMMENT 'Quantity of pharmaceutical product to be delivered as specified in the delivery order. Expressed in the base unit of measure (e.g., EA for each, BT for bottle, VL for vial).',
    `delivery_status` STRING COMMENT 'Current lifecycle status of the delivery order reflecting warehouse execution progress. Progresses from created through picking, packing, and goods issue posting. [ENUM-REF-CANDIDATE: created|picking_in_progress|picked|packing_in_progress|packed|goods_issue_posted|cancelled — promote to reference product]',
    `delivery_type` STRING COMMENT 'Classification of the delivery document indicating the nature of the movement: outbound (commercial sale), returns (reverse logistics), stock_transfer (inter-site or inter-DC), clinical_supply (investigational product for clinical trials), or sample (promotional/medical samples). Aligns with SAP delivery type (LF, LR, NL, etc.).. Valid values are `outbound|returns|stock_transfer|clinical_supply|sample`',
    `fefo_compliant` BOOLEAN COMMENT 'Indicates whether the batch/lot selected for this delivery complies with FEFO (First Expiry First Out) inventory rotation policy, ensuring the earliest-expiring stock is shipped first. Mandatory for pharmaceutical GDP compliance.',
    `goods_issue_quantity` DECIMAL(18,2) COMMENT 'Actual quantity for which goods issue has been posted in SAP, representing the confirmed shipped quantity. Used for inventory reconciliation and revenue recognition.',
    `goods_issue_status` STRING COMMENT 'Status of the SAP goods issue (GI) posting for this delivery, which triggers inventory reduction and revenue recognition. Fully posted indicates stock has been legally transferred to the customer.. Valid values are `not_posted|partial|fully_posted`',
    `goods_issue_timestamp` TIMESTAMP COMMENT 'Precise date and time when goods issue was posted in SAP SD, capturing the exact moment of inventory transfer. Required for cold-chain time-in-transit calculations and GDP audit trails.',
    `gross_weight_kg` DECIMAL(18,2) COMMENT 'Total gross weight of the delivery in kilograms, including product, primary packaging, secondary packaging, and pallet. Required for freight booking, dangerous goods documentation, and carrier compliance.',
    `handling_unit_count` STRING COMMENT 'Number of handling units (pallets, cartons, shipper boxes) packed for this delivery. Used for freight cost calculation, carrier booking, and GDP packing documentation.',
    `hazardous_material_flag` BOOLEAN COMMENT 'Indicates whether the pharmaceutical product in this delivery is classified as a hazardous material (e.g., cytotoxic, controlled substance, radioactive pharmaceutical) requiring special handling, labeling, and transport documentation.',
    `incoterms_code` STRING COMMENT 'International Commercial Terms (Incoterms 2020) code defining the transfer of risk and responsibility between seller and buyer for this delivery. Determines who bears cost and risk during transport. [ENUM-REF-CANDIDATE: EXW|FCA|CPT|CIP|DAP|DPU|DDP|FAS|FOB|CFR|CIF — 11 candidates stripped; promote to reference product]',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the delivery order record in the source system. Supports incremental data loading and change data capture in the lakehouse pipeline.',
    `packing_status` STRING COMMENT 'Packing execution status indicating whether the picked pharmaceutical goods have been packed into shipping units (cartons, pallets, shipper boxes) for this delivery.. Valid values are `not_started|partial|complete`',
    `picked_quantity` DECIMAL(18,2) COMMENT 'Actual quantity of pharmaceutical product physically picked from warehouse storage bins. May differ from delivery quantity in cases of partial picks or stock discrepancies.',
    `picking_status` STRING COMMENT 'Warehouse picking execution status indicating whether stock has been physically selected from storage bins for this delivery. Corresponds to SAP WM transfer order status.. Valid values are `not_started|partial|complete`',
    `planned_delivery_date` DATE COMMENT 'The scheduled date on which the pharmaceutical goods are planned to be delivered to the ship-to party. Used for supply chain planning and customer service level monitoring.',
    `shipment_number` STRING COMMENT 'SAP shipment document number (VT01N) associated with this delivery, representing the physical transport leg after goods issue. A single shipment may consolidate multiple delivery orders. Distinct from the delivery order which is the warehouse execution instruction.',
    `storage_condition` STRING COMMENT 'Required storage and transport temperature condition for the pharmaceutical product (e.g., refrigerated 2-8°C, frozen -20°C, ambient 15-25°C). Critical for cold-chain logistics planning and GDP compliance.. Valid values are `ambient|refrigerated|frozen|controlled_room_temp|cryogenic`',
    `temperature_excursion_flag` BOOLEAN COMMENT 'Indicates whether a temperature excursion (deviation from required storage condition) was recorded during the picking, packing, or pre-shipment staging of this delivery. Triggers quality investigation per GDP.',
    `tracking_number` STRING COMMENT 'Carrier-assigned tracking number (e.g., UPS, FedEx, DHL tracking ID) for the physical shipment associated with this delivery. Used for last-mile visibility and customer delivery confirmation.',
    `volume_m3` DECIMAL(18,2) COMMENT 'Total volume of the delivery in cubic metres. Used for freight capacity planning, cold-chain container sizing, and carrier booking.',
    CONSTRAINT pk_delivery_order PRIMARY KEY(`delivery_order_id`)
) COMMENT 'Outbound delivery document representing the fulfillment instruction for pharmaceutical finished goods against commercial orders or stock transfer requests. Captures delivery number, delivery type (outbound, returns, stock transfer), ship-to party, delivery date, material, lot number, delivery quantity, picking status, packing status, goods issue status, carrier assignment, and FEFO (First Expiry First Out) compliance flag. Aligns with SAP SD outbound delivery (VL01N). Represents the warehouse execution instruction — distinct from shipment which tracks the physical movement after goods issue.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`supply`.`distribution_network` (
    `distribution_network_id` BIGINT COMMENT 'Unique surrogate identifier for each node in the pharmaceutical distribution network topology. Serves as the primary key for this master resource record.',
    `address_id` BIGINT COMMENT 'Foreign key linking to masterdata.address. Business justification: distribution_network has denormalized address, city, latitude, longitude plain-text fields. Linking to masterdata.address enforces 3NF and enables validated address master data for GDP site qualificat',
    `country_id` BIGINT COMMENT 'Foreign key linking to masterdata.country. Business justification: distribution_network.country_code is a denormalized plain-text field. Linking to masterdata.country enables GDP authorization validation by country, distribution license requirement checks, and serial',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to masterdata.legal_entity. Business justification: Distribution network nodes are operated by or contracted to a legal entity (own warehouse or 3PL entity). Pharma GDP compliance requires knowing the responsible legal entity for each node for regulato',
    `site_id` BIGINT COMMENT 'Foreign key linking to manufacturing.site. Business justification: Supply network design and S&OP planning require knowing which manufacturing site feeds each distribution node. GDP compliance routing and capacity allocation depend on this site-to-network relationshi',
    `business_partner_id` BIGINT COMMENT 'Foreign key linking to masterdata.business_partner. Business justification: Distribution network nodes operated by 3PL providers must be linked to the operator business_partner for GDP qualification management, contract compliance, and 3PL performance reporting. distribution_',
    `clinical_supply_capable` BOOLEAN COMMENT 'Indicates whether the node is qualified and authorized to handle clinical trial investigational medicinal products (IMPs) in addition to commercial supply. Clinical supply nodes must comply with GCP and GMP requirements.',
    `cold_chain_certified` BOOLEAN COMMENT 'Indicates whether the node holds a valid cold chain certification from a recognized body (e.g., IATA CEIV Pharma, GDP cold chain qualification). Required for handling temperature-sensitive biologics, vaccines, and specialty medicines.',
    `controlled_substance_authorized` BOOLEAN COMMENT 'Indicates whether the node is authorized by the DEA (or equivalent national authority) to store and distribute controlled substances. Nodes without this authorization cannot be assigned to controlled substance distribution lanes.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this distribution network node record was first created in the system. Used for audit trail, data lineage, and compliance with 21 CFR Part 11 electronic records requirements.',
    `dea_registration_number` STRING COMMENT 'DEA registration number authorizing the node to handle Schedule I–V controlled substances. Required for US-based nodes handling controlled pharmaceutical products. Null for non-US nodes or nodes not handling controlled substances.',
    `effective_end_date` DATE COMMENT 'Date on which this distribution network node is scheduled to cease operations or be decommissioned. Null for currently active nodes with no planned end date. Used for network transition planning.',
    `effective_start_date` DATE COMMENT 'Date from which this distribution network node became or is scheduled to become operationally active in the supply network. Used for time-phased network planning and historical network topology analysis.',
    `gdp_authorization_expiry_date` DATE COMMENT 'Date on which the GDP wholesale distribution authorization expires. Supply planning systems must alert when expiry is approaching to prevent distribution through unauthorized nodes.',
    `gdp_authorization_number` STRING COMMENT 'Official GDP wholesale distribution authorization number issued by the competent regulatory authority (e.g., MHRA, national competent authority). Required for regulatory traceability and audit purposes.',
    `gdp_authorization_status` STRING COMMENT 'Current GDP authorization status of the node as required by EU GDP Guidelines (2013/C 343/01) and equivalent national regulations. Authorized nodes are eligible to handle medicinal products. Expired or suspended nodes must be excluded from active distribution lanes.. Valid values are `authorized|pending|expired|not_required|suspended`',
    `handling_time_days` STRING COMMENT 'Number of calendar days required for internal processing activities at the node (receiving, quality inspection, pick/pack, dispatch preparation). Added to lead times in supply planning calculations.',
    `hazmat_capable` BOOLEAN COMMENT 'Indicates whether the node is certified to store and handle hazardous materials including cytotoxic compounds, flammable solvents, and other regulated substances. Relevant for oncology API and certain excipient handling.',
    `inbound_lead_time_days` STRING COMMENT 'Standard number of calendar days required for inbound shipments to arrive at this node from its upstream supply source. Used as a planning parameter in Kinaxis RapidResponse and SAP APO/IBP for replenishment scheduling.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this distribution network node record was most recently modified. Used for change tracking, audit trail, and incremental data pipeline processing in the Databricks Silver Layer.',
    `multi_temperature_capable` BOOLEAN COMMENT 'Indicates whether the node can simultaneously handle multiple temperature zones (e.g., both ambient and refrigerated storage). Enables assignment of mixed-temperature product portfolios to a single node in supply network planning.',
    `network_tier` STRING COMMENT 'Hierarchical tier classification of the node within the distribution network topology. Tier 1 = primary manufacturing/central DC; Tier 2 = regional DC; Tier 3 = local/last-mile node. Drives network optimization and replenishment hierarchy in supply planning.. Valid values are `tier_1|tier_2|tier_3`',
    `node_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this distribution network node across supply chain planning systems (Kinaxis RapidResponse, Blue Yonder, SAP APO/IBP). Used as the business key for cross-system integration and network lane definitions.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `node_name` STRING COMMENT 'Human-readable name of the distribution network node (e.g., Frankfurt Regional DC, Chicago 3PL Hub, Singapore Manufacturing Site). Used in supply chain planning dashboards and network topology reports.',
    `node_status` STRING COMMENT 'Current lifecycle status of the distribution network node. Inactive or suspended nodes are excluded from supply planning runs. Nodes under qualification are pending GDP or regulatory authorization review.. Valid values are `active|inactive|suspended|under_qualification|decommissioned`',
    `node_type` STRING COMMENT 'Classification of the network node by its functional role in the pharmaceutical supply chain. Drives planning logic, GDP compliance requirements, and lane eligibility in Kinaxis RapidResponse and SAP APO/IBP. [ENUM-REF-CANDIDATE: manufacturing_site|distribution_center|3pl_node|wholesaler|direct_to_pharmacy|clinical_depot|hospital_pharmacy|specialty_pharmacy — promote to reference product]. Valid values are `manufacturing_site|distribution_center|3pl_node|wholesaler|direct_to_pharmacy|clinical_depot`',
    `notes` STRING COMMENT 'Free-text field for capturing operational notes, special handling instructions, or qualifications relevant to this distribution network node. Examples include specific GDP deviation history, special import/export restrictions, or infrastructure constraints.',
    `operator_type` STRING COMMENT 'Classification of the entity operating the distribution node. Distinguishes between internally operated sites and third-party operators such as 3PL (Third-Party Logistics), CMO (Contract Manufacturing Organization), CDMO (Contract Development and Manufacturing Organization), or wholesalers.. Valid values are `internal|3pl|cmo|cdmo|wholesaler|distributor`',
    `outbound_lead_time_days` STRING COMMENT 'Standard number of calendar days required for outbound shipments to depart this node and reach the next downstream node or customer. Used for delivery commitment and supply planning in Kinaxis RapidResponse.',
    `pallet_capacity` STRING COMMENT 'Maximum number of standard pallets (EUR/ISO pallet) the node can accommodate simultaneously. Used for operational capacity planning and inbound/outbound throughput modeling in supply network planning tools.',
    `quarantine_zone_available` BOOLEAN COMMENT 'Indicates whether the node has a dedicated physical quarantine zone for holding materials pending quality release, investigation, or returns processing. Required for GDP-compliant nodes handling pharmaceutical products.',
    `region` STRING COMMENT 'Internal geographic region classification for the node (e.g., EMEA, APAC, North America, LATAM). Used for regional supply planning segmentation in Kinaxis RapidResponse and Blue Yonder.',
    `sap_plant_code` STRING COMMENT 'Four-character SAP plant code assigned to this distribution network node in SAP S/4HANA MM/WM/PP modules. Used for cross-system integration between supply planning tools (Kinaxis, Blue Yonder) and SAP ERP for inventory and production order management.. Valid values are `^[A-Z0-9]{4}$`',
    `sap_storage_location_code` STRING COMMENT 'SAP storage location code within the plant, representing the primary storage location for this node in SAP S/4HANA WM. Used for inventory posting, goods receipt, and goods issue transactions.. Valid values are `^[A-Z0-9]{4}$`',
    `serialization_capable` BOOLEAN COMMENT 'Indicates whether the node is equipped to scan, verify, and process serialized pharmaceutical packaging as required by DSCSA (US) and EU FMD (Falsified Medicines Directive) track-and-trace regulations.',
    `storage_capacity_m3` DECIMAL(18,2) COMMENT 'Total physical storage capacity of the node measured in cubic meters. Used for capacity planning, network optimization, and inventory allocation decisions in Kinaxis RapidResponse and SAP WM.',
    `temperature_zone` STRING COMMENT 'Primary temperature storage zone capability of the node. Defines the cold-chain handling classification: ambient (15–25°C), CRT (Controlled Room Temperature, 15–30°C), refrigerated (2–8°C), frozen (-20°C), or ultra-low temperature (-80°C). Critical for product-to-node assignment in supply planning.. Valid values are `ambient|crt|refrigerated_2_8c|frozen_minus_20c|ultra_low_minus_80c`',
    `warehouse_zone_count` STRING COMMENT 'Number of distinct storage zones configured within the node (e.g., quarantine zone, approved stock zone, returns zone, controlled substance vault). Reflects the physical warehouse layout complexity in SAP WM.',
    CONSTRAINT pk_distribution_network PRIMARY KEY(`distribution_network_id`)
) COMMENT 'Master record defining the pharmaceutical distribution network topology including manufacturing sites, distribution centers, 3PL nodes, wholesalers, direct-to-pharmacy lanes, and warehouse storage zones with bin/rack/zone configuration. Captures node type, node name, geographic region, GDP authorization status, cold-chain capability (temperature zones: ambient, CRT, 2-8°C, -20°C, -80°C), controlled substance handling authorization, storage capacity, physical warehouse layout, lead times, and network lane definitions. Used for supply network planning in Kinaxis RapidResponse/Blue Yonder and SAP APO/IBP.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`supply`.`clinical_supply_order` (
    `clinical_supply_order_id` BIGINT COMMENT 'Unique surrogate identifier for the clinical supply order record in the lakehouse Silver layer. Primary key for this entity.',
    `batch_record_id` BIGINT COMMENT 'Foreign key linking to manufacturing.batch_record. Business justification: QP release for clinical trial supplies requires the batch record to be directly referenced on the clinical supply order. EU GMP Annex 13 and FDA 21 CFR Part 312 mandate batch record traceability for i',
    `compound_id` BIGINT COMMENT 'Foreign key linking to discovery.compound. Business justification: Clinical trials order specific investigational compounds identified in IND/CTA applications. Essential for clinical supply chain management linking discovery assets to trial execution, regulatory subm',
    `business_partner_id` BIGINT COMMENT 'Foreign key linking to masterdata.business_partner. Business justification: clinical_supply_order.courier_name is a denormalized plain-text field. Linking to masterdata.business_partner enables courier qualification tracking, GDP compliance verification, and clinical supply c',
    `country_id` BIGINT COMMENT 'Foreign key linking to masterdata.country. Business justification: clinical_supply_order.destination_country_code is a denormalized plain-text field. Linking to masterdata.country enables import permit validation, clinical trial regulatory compliance checks, and coun',
    `distribution_network_id` BIGINT COMMENT 'Foreign key linking to supply.distribution_network. Business justification: clinical_supply_order has supply_depot_code as a free-text string identifying the supply depot from which the IMP is shipped. Adding distribution_network_id → distribution_network.distribution_network',
    `drug_product_id` BIGINT COMMENT 'Foreign key linking to product.drug_product. Business justification: Clinical supply orders must reference the investigational drug product for IND/CTA regulatory compliance, QP release documentation, and clinical trial supply chain traceability. A clinical supply expe',
    `formulation_id` BIGINT COMMENT 'Foreign key linking to product.formulation. Business justification: Clinical supply orders must specify the exact formulation version for blinding integrity, dose preparation instructions, and regulatory submission (IND/CTA CMC section). Different formulation versions',
    `internal_order_id` BIGINT COMMENT 'Foreign key linking to finance.internal_order. Business justification: Clinical supply costs (IMP manufacturing, packaging, distribution) are charged to clinical trial internal orders for R&D cost accounting. Required for trial budget tracking, capitalization decisions, ',
    `inventory_lot_id` BIGINT COMMENT 'Foreign key linking to supply.inventory_lot. Business justification: Clinical supply orders are fulfilled from specific inventory lots of investigational products. The lot_number (STRING) should be replaced with inventory_lot_id FK to inventory_lot.inventory_lot_id. Ma',
    `investigational_product_id` BIGINT COMMENT 'Reference to the investigational medicinal product (IMP) master record being ordered. Captures the IMP material code as defined in the clinical supply catalogue and aligned with the IND/CTA filing.',
    `investigational_site_id` BIGINT COMMENT 'Reference to the investigational site that will receive the clinical supply shipment. Identifies the physical location (hospital, clinic, research centre) conducting the trial.',
    `investigator_id` BIGINT COMMENT 'Foreign key linking to hcp.investigator. Business justification: GCP/ICH E6 drug accountability requires every clinical supply order to be traceable to the responsible investigator. FDA inspections and drug accountability logs mandate this link. No existing FK cove',
    `licensing_agreement_id` BIGINT COMMENT 'Foreign key linking to intellectual.licensing_agreement. Business justification: Clinical supply orders for in-licensed compounds must reference the licensing agreement to confirm clinical use is within the licensed field-of-use and territory. IP and clinical operations teams veri',
    `patent_id` BIGINT COMMENT 'Foreign key linking to intellectual.patent. Business justification: Clinical supply orders for investigational products are tied to specific patents protecting the compound under study. IP teams track which patents cover clinical-stage compounds to manage prosecution ',
    `patient_enrollment_id` BIGINT COMMENT 'Foreign key linking to patient.patient_enrollment. Business justification: Supply orders must verify enrollment status (active, consented) before shipping investigational product. Links order to specific trial enrollment context (site, protocol version, treatment arm) requir',
    `plan_id` BIGINT COMMENT 'Foreign key linking to supply.plan. Business justification: Clinical supply orders for IMPs and comparators are driven by clinical supply plans. Linking clinical_supply_order.plan_id → plan.plan_id connects clinical supply execution to the supply plan, enablin',
    `production_order_id` BIGINT COMMENT 'Foreign key linking to manufacturing.production_order. Business justification: Clinical supply orders drive manufacturing of investigational products. IND/CTA regulatory submissions and QP release require direct traceability from the clinical supply order to the production order',
    `project_id` BIGINT COMMENT 'Foreign key linking to discovery.project. Business justification: Clinical supply orders are executed under a discovery/development project for budget allocation, protocol management, and regulatory tracking. Supply teams reference the project for SAP WBS elements a',
    `protocol_id` BIGINT COMMENT 'Foreign key linking to clinical.protocol. Business justification: Clinical supply orders are placed against a specific protocol version. Protocol amendments (dose changes, sample size) drive supply order amendments. Linking to protocol_id allows supply teams to trac',
    `trial_id` BIGINT COMMENT 'Foreign key linking to clinical.trial. Business justification: All clinical supply orders are placed under a specific trial. A direct trial_id FK enables supply operations to report all orders, quantities, and costs per trial for IND annual reports and clinical s',
    `unit_of_measure_id` BIGINT COMMENT 'Foreign key linking to masterdata.unit_of_measure. Business justification: clinical_supply_order.quantity_unit_of_measure is a denormalized plain-text UOM. Linking to masterdata.unit_of_measure enforces 3NF and ensures validated UOM master data for IRT system reconciliation ',
    `actual_delivery_date` DATE COMMENT 'The date on which the clinical supply was confirmed as received at the investigational site. Compared against required_delivery_date to assess supply chain performance and site readiness.',
    `approved_quantity` DECIMAL(18,2) COMMENT 'The quantity of IMP or ancillary supply formally approved for fulfilment after clinical supply review. May differ from ordered_quantity due to stock availability, protocol amendments, or QP release constraints.',
    `blinding_type` STRING COMMENT 'Specifies the blinding methodology applied to this supply order as defined in the clinical protocol. Determines labelling, packaging, and handling requirements for the IMP to maintain trial integrity.. Valid values are `Open-Label|Single-Blind|Double-Blind|Triple-Blind|Not Applicable`',
    `cancellation_reason` STRING COMMENT 'Free-text description of the reason for cancellation when order_status is Cancelled. Captures business justification for audit trail and supply planning analysis (e.g., protocol amendment, site closure, stock recall).',
    `cold_chain_required` BOOLEAN COMMENT 'Indicates whether this supply order requires cold-chain logistics (True) due to temperature-sensitive IMP storage and transport conditions. Triggers cold-chain packaging, monitoring, and carrier selection in the distribution workflow.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this clinical supply order record was first created in the system, in ISO 8601 format with timezone offset. Supports audit trail requirements under 21 CFR Part 11 and EU Annex 11.',
    `dispensing_unit` STRING COMMENT 'Description of the dispensing unit configuration for the IMP as packaged for clinical trial use (e.g., Blinded kit of 28 tablets, 1 vial 10mg/mL). Supports site pharmacist dispensing and accountability records.',
    `export_permit_number` STRING COMMENT 'Reference number of the export permit or authorisation issued by the originating countrys regulatory authority for the shipment of IMP across international borders for clinical trial purposes.',
    `import_permit_number` STRING COMMENT 'Reference number of the import permit issued by the relevant national regulatory authority (e.g., FDA, EMA member state, PMDA) authorising the importation of the IMP into the destination country for clinical trial use.',
    `ind_cta_number` STRING COMMENT 'The regulatory filing reference number (IND number in the US per 21 CFR Part 312, or CTA number in the EU per Regulation 536/2014) under which this clinical supply order is authorised. Required for import/export permit applications and regulatory compliance.',
    `irt_system_reference` STRING COMMENT 'Reference number or transaction ID from the Interactive Response Technology (IRT) / Interactive Web Response System (IWRS) that triggered or confirmed this supply order. Links the supply event to the randomization and drug management system.',
    `is_blinded` BOOLEAN COMMENT 'Indicates whether this supply order is subject to blinding requirements (True) or is open-label (False). Used as a quick filter for blinding compliance checks and supply handling procedures.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time when this clinical supply order record was most recently modified, in ISO 8601 format with timezone offset. Required for change control audit trail under 21 CFR Part 11 and EU Annex 11.',
    `order_date` DATE COMMENT 'The calendar date on which the clinical supply order was formally placed or submitted by the clinical supply team. This is the principal business event date for the order.',
    `order_number` STRING COMMENT 'Externally-known, human-readable order reference number assigned by the clinical supply management system (e.g., Kinaxis RapidResponse or SAP MM) to uniquely identify this supply order across systems and with third-party logistics providers.. Valid values are `^CSO-[A-Z0-9]{4,20}$`',
    `order_status` STRING COMMENT 'Current lifecycle state of the clinical supply order, tracking progression from initial creation through fulfilment or cancellation. Drives supply chain workflow in Kinaxis RapidResponse / SAP MM. [ENUM-REF-CANDIDATE: Draft|Submitted|Approved|In Preparation|Shipped|Delivered|Cancelled|On Hold — promote to reference product]',
    `order_type` STRING COMMENT 'Classification of the supply order by the nature of the material being ordered. IMP = investigational medicinal product; Comparator = approved reference drug; Placebo = matching placebo; Ancillary = non-IMP study supplies; Open-Label Extension = OLE phase supply; Rescue Medication = emergency/rescue supply.. Valid values are `IMP|Comparator|Placebo|Ancillary|Open-Label Extension|Rescue Medication`',
    `ordered_quantity` DECIMAL(18,2) COMMENT 'The quantity of IMP or ancillary supply units requested in this order, expressed in the unit of measure defined on the IMP material master (e.g., vials, tablets, kits).',
    `priority_level` STRING COMMENT 'Priority classification of the clinical supply order indicating the urgency of fulfilment. Emergency orders may be triggered by unplanned site demand, protocol deviations, or patient safety requirements.. Valid values are `Routine|Urgent|Emergency`',
    `qp_release_date` DATE COMMENT 'The date on which the Qualified Person (QP) formally certified and released the IMP batch for clinical use. Required for EU GMP Annex 13 compliance and batch disposition records.',
    `qualified_person_release` BOOLEAN COMMENT 'Indicates whether the IMP batch included in this order has been certified and released by a Qualified Person (QP) as required by EU GMP Annex 13 and Directive 2001/20/EC before dispatch to the clinical site.',
    `randomization_kit_number` STRING COMMENT 'The unique kit number assigned by the Interactive Response Technology (IRT) or randomization system to the blinded supply kit. Links the physical supply to the randomization schedule and subject assignment. Critical for blinded trial integrity.',
    `required_delivery_date` DATE COMMENT 'The date by which the clinical supply must arrive at the investigational site to support the trial schedule. Used for supply chain planning and lead-time management in Kinaxis RapidResponse.',
    `shipment_date` DATE COMMENT 'The date on which the clinical supply was physically dispatched from the originating depot or manufacturing site. Used for GDP compliance, transit time tracking, and delivery performance monitoring.',
    `shipped_quantity` DECIMAL(18,2) COMMENT 'The actual quantity of IMP or ancillary supply physically dispatched from the manufacturing site or depot. May differ from approved_quantity due to last-minute stock adjustments or partial shipments.',
    `shipping_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the country from which the clinical supply is dispatched. Used for import/export compliance, customs documentation, and GDP route planning.. Valid values are `^[A-Z]{3}$`',
    `storage_temperature_max_c` DECIMAL(18,2) COMMENT 'The maximum permissible storage and transport temperature in degrees Celsius for the IMP in this order, as specified in the IMP dossier and CoA. Used to configure cold-chain monitoring thresholds and excursion alerts.',
    `storage_temperature_min_c` DECIMAL(18,2) COMMENT 'The minimum permissible storage and transport temperature in degrees Celsius for the IMP in this order, as specified in the IMP dossier and CoA. Used to configure cold-chain monitoring thresholds.',
    `tracking_number` STRING COMMENT 'The courier or logistics providers shipment tracking reference number, enabling real-time monitoring of the clinical supply in transit. Supports GDP compliance and cold-chain excursion investigation.',
    CONSTRAINT pk_clinical_supply_order PRIMARY KEY(`clinical_supply_order_id`)
) COMMENT 'Supply order for investigational medicinal products (IMPs), comparators, and ancillary supplies destined for clinical trial sites. Captures IMP material code, protocol number, study site, randomization kit number, ordered quantity, blinding requirements, expiry date, cold-chain requirements, import/export permit references, and order status. Distinct from commercial sales orders due to IND/CTA regulatory requirements, blinding, and randomization constraints.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`supply`.`product_recall` (
    `product_recall_id` BIGINT COMMENT 'Unique system-generated identifier for the pharmaceutical product recall event record. Primary key for the product_recall data product in the supply domain.',
    `approval_id` BIGINT COMMENT 'Foreign key linking to regulatory.approval. Business justification: Product recalls are initiated against a specific regulatory approval — the recall targets the approved product/indication. Regulatory affairs teams track which approval is being recalled for health au',
    `batch_record_id` BIGINT COMMENT 'Foreign key linking to manufacturing.batch_record. Business justification: Product recalls are initiated based on quality findings documented in batch records. FDA 21 CFR Part 7 recall submissions require direct reference to the implicated batch record. No existing column on',
    `brand_id` BIGINT COMMENT 'Foreign key linking to commercial.brand. Business justification: Recalls are managed at brand level; commercial teams coordinate customer notifications, field force communications, and market impact assessments. Links recall events to brand positioning, promotional',
    `brand_plan_id` BIGINT COMMENT 'Foreign key linking to commercial.brand_plan. Business justification: Product recalls must be assessed against the active brand plan to quantify commercial revenue impact, update forecasts, and trigger regulatory/commercial communications. FDA recall effectiveness repor',
    `country_id` BIGINT COMMENT 'Foreign key linking to masterdata.country. Business justification: Product recalls are executed per country with country-specific regulatory notification requirements (FDA, EMA, PMDA). A country FK on product_recall is essential for regulatory notification tracking a',
    `coverage_decision_id` BIGINT COMMENT 'Foreign key linking to market.coverage_decision. Business justification: Product recall regulatory process requires notifying payers and suspending affected coverage decisions. Market access teams must identify which coverage decisions are impacted by a recall for regulato',
    `drug_master_file_id` BIGINT COMMENT 'Foreign key linking to intellectual.drug_master_file. Business justification: During a product recall, regulatory teams reference the DMF to identify manufacturing site details, API specifications, and CMC data relevant to the recall root cause. Recall regulatory submissions to',
    `drug_product_id` BIGINT COMMENT 'Foreign key linking to product.drug_product. Business justification: Recalls target specific drug product formulations/strengths, not just medicinal product families. Batch-level recall execution requires drug_product specificity for lot identification, customer notifi',
    `internal_order_id` BIGINT COMMENT 'Foreign key linking to finance.internal_order. Business justification: Recall cost collection: product recalls require a dedicated internal order (cost collector) to capture all recall-related costs — logistics, destruction, customer credits, regulatory fees — for financ',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to masterdata.legal_entity. Business justification: Product recalls are initiated and managed by a specific legal entity responsible for regulatory notifications and liability. Pharma regulatory affairs teams require legal entity attribution for recall',
    `line_id` BIGINT COMMENT 'Foreign key linking to manufacturing.line. Business justification: Recalls are frequently scoped to a specific manufacturing line (e.g., contamination event on Line 3). FDA recall scope definition and effectiveness checks require direct line-level scoping on the reca',
    `manufacturing_deviation_id` BIGINT COMMENT 'Foreign key linking to manufacturing.manufacturing_deviation. Business justification: Manufacturing deviations are a primary trigger for product recalls. Regulatory CAPA closure and FDA/EMA recall submissions require direct linkage between the causative deviation and the resulting reca',
    `master_batch_record_id` BIGINT COMMENT 'Foreign key linking to manufacturing.master_batch_record. Business justification: Recalls triggered by a defective MBR version (wrong formulation, incorrect specifications) require direct linkage to the implicated MBR. QA must identify all batches produced under that MBR version fo',
    `material_id` BIGINT COMMENT 'Foreign key linking to masterdata.material. Business justification: Recalls must link to material master for affected specifications, regulatory data, distribution history. Critical for recall scope determination, effectiveness checks, regulatory reporting, and custom',
    `medicinal_product_id` BIGINT COMMENT 'Reference to the master product record for the pharmaceutical product subject to the recall. Links to the product master data entity for product name, formulation, and therapeutic area details.',
    `packaging_configuration_id` BIGINT COMMENT 'Foreign key linking to product.packaging_configuration. Business justification: Recalls in pharma are often packaging-configuration-specific (e.g., a specific blister pack size with a defective closure). FDA/EMA recall notifications require precise packaging identification. Direc',
    `patient_access_program_id` BIGINT COMMENT 'Foreign key linking to market.patient_access_program. Business justification: When a product recall is initiated, patient access programs dispensing the recalled product must be immediately suspended and enrolled patients notified. Patient safety compliance requires direct trac',
    `pv_product_id` BIGINT COMMENT 'Foreign key linking to pharmacovigilance.pv_product. Business justification: Product recalls are often triggered by safety signals (ICSRs, SUSARs) and require coordination between supply chain and pharmacovigilance for regulatory authority notifications (FDA, EMA). Links recal',
    `reimbursement_policy_id` BIGINT COMMENT 'Foreign key linking to market.reimbursement_policy. Business justification: Regulatory recall notifications must identify affected reimbursement policies for suspension or amendment. Health authorities and payers require traceability from recall events to active reimbursement',
    `safety_signal_id` BIGINT COMMENT 'Foreign key linking to pharmacovigilance.safety_signal. Business justification: Product recalls in pharma are formally triggered by validated safety signals. Regulatory agencies (FDA, EMA) require traceability from recall action back to the originating safety signal. PV and suppl',
    `site_id` BIGINT COMMENT 'Reference to the manufacturing site where the affected lots were produced. Enables traceability back to the production facility for root cause investigation and regulatory inspection purposes.',
    `sku_id` BIGINT COMMENT 'Foreign key linking to product.sku. Business justification: Product recalls in pharma are executed at SKU level — the specific market pack (country, strength, pack size) determines customer notification scope and regulatory reporting. sku_code is denormalized;',
    `trial_id` BIGINT COMMENT 'Foreign key linking to clinical.trial. Business justification: Recall management requires identifying all active clinical trials using the recalled product/lot. Linking product_recall to trial enables recall teams to notify sponsors, pause dosing, and file regula',
    `affected_markets` STRING COMMENT 'Comma-separated list of ISO 3-letter country codes (e.g., USA, GBR, DEU) identifying the countries or markets where the recalled product was distributed and where recall actions must be executed.',
    `cold_chain_required` BOOLEAN COMMENT 'Indicates whether the recalled product requires cold-chain handling (temperature-controlled logistics) during the recovery and return process. Critical for biologics, vaccines, and temperature-sensitive drug products.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when the product recall record was first created in the system. Audit trail field supporting 21 CFR Part 11 electronic records compliance and data lineage tracking.',
    `customer_notification_date` DATE COMMENT 'The date on which direct customers (wholesalers, distributors, hospitals, pharmacies) were formally notified of the recall via recall notification letters or electronic communications.',
    `customer_notification_status` STRING COMMENT 'Current status of the customer notification process indicating whether recall notification letters have been sent to all affected customers in the distribution chain.. Valid values are `Not Started|In Progress|Completed|Partially Completed`',
    `distribution_level` STRING COMMENT 'The level in the distribution chain to which the recall extends. Consumer: product reached end patients/consumers; Retail: product at retail pharmacy level; Wholesale: product at wholesale distributor level; Hospital: product at hospital/clinic level; User: product at healthcare professional level.. Valid values are `Consumer|Retail|Wholesale|Hospital|User`',
    `effectiveness_check_level` STRING COMMENT 'FDA-defined effectiveness check level indicating the depth and percentage of consignees to be audited to verify recall notification receipt and product return. Level A: 100% of consignees; Level B: some percentage; Level C: 10% of consignees; Level D: 2% of consignees; Not Required: for certain recall types.. Valid values are `Level A|Level B|Level C|Level D|Not Required`',
    `expiration_date_range` STRING COMMENT 'The expiration date range (e.g., 2024-01 to 2025-06) covering all affected lot numbers included in the recall. Assists customers and distributors in identifying recalled product on shelves and in inventory.',
    `gdp_compliance_flag` BOOLEAN COMMENT 'Indicates whether the recall execution is being conducted in compliance with Good Distribution Practice (GDP) guidelines, including proper documentation, chain of custody, and temperature-controlled handling of recovered product where applicable.',
    `health_hazard_assessment` STRING COMMENT 'Summary of the health hazard evaluation conducted by the companys medical and regulatory teams to assess the risk to patients from the defective product. Supports recall classification and regulatory submission under 21 CFR Part 7.',
    `initiating_agency` STRING COMMENT 'The regulatory authority or company entity that initiated or mandated the recall. Identifies whether the recall was company-initiated (voluntary) or directed by a specific regulatory body such as FDA, EMA, MHRA, PMDA, or NMPA. [ENUM-REF-CANDIDATE: FDA|EMA|MHRA|PMDA|NMPA|WHO|Company — 7 candidates stripped; promote to reference product]',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The timestamp when the product recall record was most recently modified. Supports audit trail requirements under 21 CFR Part 11 and enables change tracking for regulatory inspection readiness.',
    `ndc_code` STRING COMMENT 'The National Drug Code (NDC) of the affected drug product in the standard 5-4-2 format. Uniquely identifies the labeler, product, and package configuration of the recalled pharmaceutical product as registered with the FDA.. Valid values are `^[0-9]{5}-[0-9]{4}-[0-9]{2}$`',
    `press_release_date` DATE COMMENT 'The date on which the company issued a public press release or public notification regarding the recall. Required for Class I and certain Class II recalls to inform consumers and healthcare professionals.',
    `product_disposition` STRING COMMENT 'The approved method for disposing of recovered recalled product. Options include destruction, return to manufacturer, reprocessing, relabeling (where permitted), or quarantine pending further evaluation.. Valid values are `Destroy|Return to Manufacturer|Reprocess|Relabel|Quarantine`',
    `quantity_distributed` DECIMAL(18,2) COMMENT 'Total quantity of the affected product that was distributed to the market prior to the recall initiation, expressed in the standard unit of measure (e.g., units, bottles, vials). Used to calculate recall effectiveness and track recovery progress.',
    `quantity_recovered` DECIMAL(18,2) COMMENT 'Total quantity of the recalled product that has been physically returned, destroyed, or otherwise accounted for as of the last update. Used to calculate recall effectiveness percentage and support regulatory reporting.',
    `quantity_uom` STRING COMMENT 'Unit of measure applicable to quantity_distributed and quantity_recovered fields (e.g., EA=Each, BT=Bottle, VL=Vial, AMP=Ampoule, PKG=Package, KG=Kilogram, L=Liter). [ENUM-REF-CANDIDATE: EA|BT|VL|AMP|PKG|KG|L — 7 candidates stripped; promote to reference product]',
    `recall_class` STRING COMMENT 'FDA-defined classification indicating the severity of the health hazard associated with the recalled product. Class I: serious adverse health consequences or death; Class II: temporary or medically reversible adverse health consequences; Class III: unlikely to cause adverse health consequences.. Valid values are `Class I|Class II|Class III`',
    `recall_closure_date` DATE COMMENT 'The date on which the recall was formally closed or terminated by the regulatory authority or the company after all recall activities, effectiveness checks, and documentation requirements were completed.',
    `recall_effectiveness_pct` DECIMAL(18,2) COMMENT 'Percentage of distributed product that has been successfully recovered or accounted for, calculated as (quantity_recovered / quantity_distributed) * 100. Key metric for FDA recall effectiveness checks and regulatory reporting under 21 CFR Part 7.',
    `recall_initiated_date` DATE COMMENT 'The date on which the recall was formally initiated by the company or ordered by the regulatory authority. Represents the principal business event timestamp for the recall lifecycle.',
    `recall_notes` STRING COMMENT 'Free-text field for additional operational notes, regulatory correspondence summaries, or contextual information relevant to the recall event that is not captured in structured fields.',
    `recall_number` STRING COMMENT 'Externally-assigned recall identification number issued by the regulatory authority (e.g., FDA recall number) or internally assigned by the company for voluntary recalls. Serves as the primary business identifier for tracking and referencing the recall event across regulatory submissions and communications.',
    `recall_reason_code` STRING COMMENT 'Standardized code categorizing the root cause or reason for the recall (e.g., contamination, labeling error, sub-potency, sterility failure, foreign particulate). Aligns with FDA recall reason taxonomy for regulatory reporting and trend analysis. [ENUM-REF-CANDIDATE: Contamination|Labeling Error|Sub-Potency|Super-Potency|Sterility Failure|Foreign Particulate|Stability Failure|Packaging Defect|Microbial Contamination|Other — promote to reference product]',
    `recall_reason_description` STRING COMMENT 'Detailed narrative description of the specific defect, violation, or safety concern that triggered the recall. Provides the full technical and regulatory context beyond the recall reason code, including root cause findings from CAPA investigations.',
    `recall_scope` STRING COMMENT 'Geographic scope of the recall indicating whether the recall covers the entire national market, specific regions, international markets, or is limited to a specific manufacturing or distribution site.. Valid values are `Nationwide|Regional|International|Site-Specific`',
    `recall_status` STRING COMMENT 'Current lifecycle status of the recall event. Pending: recall initiated but not yet active; Active: recall in progress with field corrections underway; Monitoring: recall effectiveness checks ongoing; Terminated: FDA has terminated the recall; Closed: all recall activities completed and documented.. Valid values are `Pending|Active|Monitoring|Terminated|Closed`',
    `recall_strategy` STRING COMMENT 'Description of the recall strategy approved by the regulatory authority or company, including the depth of recall, communication methods, effectiveness check methodology, and disposition instructions for recovered product.',
    `recall_type` STRING COMMENT 'Categorization of the recall initiation type. Voluntary recalls are company-initiated; Mandatory recalls are ordered by a regulatory authority; Market Withdrawal involves minor violations not subject to legal action; Stock Recovery involves products not yet distributed to the market.. Valid values are `Voluntary|Mandatory|Market Withdrawal|Stock Recovery`',
    `regulatory_notification_date` DATE COMMENT 'The date on which the company formally notified the relevant regulatory authority (e.g., FDA, EMA) of the recall initiation. Critical compliance milestone tracked under 21 CFR Part 7 and equivalent international regulations.',
    `regulatory_submission_ref` STRING COMMENT 'Reference number or identifier for the regulatory submission (e.g., NDA, BLA, MAA) associated with the recalled product. Links the recall event to the products regulatory dossier for compliance tracking in RIMS.',
    CONSTRAINT pk_product_recall PRIMARY KEY(`product_recall_id`)
) COMMENT 'Pharmaceutical product recall event record initiated by regulatory authority mandate or voluntary company action. Captures recall number, recall class (Class I, II, III per FDA), affected NDC, affected lot numbers, recall scope (market, distribution level), recall reason, regulatory agency notification date, press release date, customer notification status, quantity recovered, and recall closure date. Supports lot traceability and regulatory reporting obligations under 21 CFR Part 7.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`supply`.`serialization_record` (
    `serialization_record_id` BIGINT COMMENT 'Primary key for serialization_record',
    `batch_record_id` BIGINT COMMENT 'Foreign key linking to manufacturing.batch_record. Business justification: Serialized units must trace to manufacturing batch. DSCSA and EU FMD regulations mandate linking serial numbers to batch records for product authentication, verification, and targeted recall execution',
    `brand_id` BIGINT COMMENT 'Foreign key linking to commercial.brand. Business justification: Serialization compliance (DSCSA, FMD) is brand-specific; commercial teams use serialization data for product authentication, counterfeit prevention, and market-specific regulatory reporting. Links tra',
    `business_partner_id` BIGINT COMMENT 'Reference to the trading partner (manufacturer, wholesaler, distributor, pharmacy) that currently holds legal ownership of the serialized unit. Updated at each DSCSA transaction event (Transfer of Ownership). Core to DSCSA chain-of-custody tracking.',
    `plant_id` BIGINT COMMENT 'Foreign key linking to masterdata.plant. Business justification: Serialization commissioning occurs at plants; plant master data provides GMP certification, FDA establishment identifier, regulatory market authorization. Distinct from manufacturing_site_id (manufact',
    `country_id` BIGINT COMMENT 'Foreign key linking to masterdata.country. Business justification: serialization_record.market_country_code is a denormalized plain-text field. Linking to masterdata.country enables EU FMD and DSCSA serialization compliance validation by market country and supports r',
    `master_id` BIGINT COMMENT 'Foreign key linking to hcp.master. Business justification: DSCSA track-and-trace and anti-diversion programs require serialized units to be traceable to the dispensing or administering HCP. Role-prefix dispensing_ distinguishes from patient_id already on th',
    `drug_product_id` BIGINT COMMENT 'Reference to the pharmaceutical finished goods product master record. Links the serialized unit to the products regulatory approvals, storage conditions, and supply chain attributes.',
    `inventory_lot_id` BIGINT COMMENT 'Foreign key linking to supply.inventory_lot. Business justification: Serialization records track individual serialized units that belong to specific inventory lots. The lot_number (STRING) should be replaced with inventory_lot_id FK to inventory_lot.inventory_lot_id. N',
    `investigational_product_id` BIGINT COMMENT 'Foreign key linking to clinical.investigational_product. Business justification: Serialized IMP packs must be linked to the specific investigational product for DSCSA/FMD track-and-trace compliance. Regulatory serialization requirements for clinical supplies mandate that each seri',
    `packaging_configuration_id` BIGINT COMMENT 'Foreign key linking to product.packaging_configuration. Business justification: Serialization occurs at specific packaging levels (bottle, carton, case, pallet). Packaging configuration defines GTIN structure, aggregation hierarchy, and regulatory serialization requirements (DSCS',
    `patient_id` BIGINT COMMENT 'Foreign key linking to patient.patient. Business justification: Clinical supply serialization systems track which specific serialized unit (GTIN/serial) was dispensed to which patient. Required for accountability, returns reconciliation, regulatory inspections, an',
    `site_id` BIGINT COMMENT 'Reference to the manufacturing or packaging site where the serial number was commissioned. Used for GDP compliance, site-level traceability, and regulatory reporting to FDA/EMA.',
    `product_recall_id` BIGINT COMMENT 'Reference to the recall event record when recall_flag is TRUE. Links the serialized unit to the specific recall notification, recall class, and remediation actions. Populated only when the unit is subject to an active recall.',
    `sales_order_id` BIGINT COMMENT 'Foreign key linking to commercial.sales_order. Business justification: DSCSA (Drug Supply Chain Security Act) compliance requires tracing serialized pharmaceutical units to the sales transaction. Pharma serialization teams link serial numbers to sales orders for transact',
    `shipment_id` BIGINT COMMENT 'Foreign key linking to supply.shipment. Business justification: A serialization record tracks the unit-level and case-level serialization status of pharmaceutical finished goods. When a serialized unit is shipped, the serialization record should be linked to the s',
    `sku_id` BIGINT COMMENT 'Foreign key linking to product.sku. Business justification: DSCSA (US) and FMD (EU) serialization regulations require saleable unit identification at SKU level. Serialization records must reference the SKU to support verification, aggregation hierarchy, and re',
    `storage_location_id` BIGINT COMMENT 'Reference to the physical location (warehouse, distribution center, pharmacy, hospital) where the serialized unit is currently held. Used for inventory visibility, GDP compliance, and cold-chain monitoring.',
    `treatment_exposure_id` BIGINT COMMENT 'Foreign key linking to patient.treatment_exposure. Business justification: Links serialized investigational product units to documented treatment administration events in eCRF. Enables verification that lot/serial numbers recorded in exposure logs match dispensed units, crit',
    `cold_chain_required` BOOLEAN COMMENT 'Indicates whether this serialized unit requires cold-chain storage and transportation (e.g., 2-8°C refrigerated or -20°C frozen). Drives cold-chain logistics routing, temperature monitoring requirements, and GDP compliance checks.',
    `commissioning_event_timestamp` TIMESTAMP COMMENT 'Date and time when the serial number was commissioned (activated and associated with a physical product unit) at the manufacturing or packaging site. Marks the start of the serialized units lifecycle. Required for DSCSA and EU FMD event reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this serialization record was first created in the enterprise data platform. Represents the audit trail creation timestamp for the Silver Layer record, distinct from the commissioning event timestamp.',
    `decommissioning_reason` STRING COMMENT 'Reason code for decommissioning the serialized unit. Required for EU FMD decommissioning event reporting to the European Medicines Verification System (EMVS). Supports pharmacovigilance and recall management workflows. [ENUM-REF-CANDIDATE: recall|destruction|sample|theft|damage|dispensed|exported|other — promote to reference product]',
    `decommissioning_timestamp` TIMESTAMP COMMENT 'Date and time when the serialized unit was decommissioned (removed from the active supply chain). Populated when serialization_status transitions to decommissioned or destroyed. Required for EU FMD and DSCSA event reporting.',
    `dosage_form` STRING COMMENT 'Pharmaceutical dosage form of the product (e.g., tablet, capsule, injection, solution). Used for supply chain classification, storage condition assignment, and regulatory reporting. [ENUM-REF-CANDIDATE: tablet|capsule|injection|solution|cream|patch|inhaler|suspension — promote to reference product]',
    `epcis_event_code` STRING COMMENT 'Unique identifier of the most recent GS1 EPCIS event associated with this serialized unit. Links to the EPCIS event repository for full event history (ObjectEvent, AggregationEvent, TransactionEvent). Used for DSCSA and EU FMD interoperability.',
    `gdp_compliance_flag` BOOLEAN COMMENT 'Indicates whether the current handling and storage of this serialized unit is compliant with Good Distribution Practice (GDP) requirements. Set to FALSE if a GDP deviation has been recorded for this unit (e.g., temperature excursion, unauthorized handling).',
    `gtin` STRING COMMENT '14-digit GS1 Global Trade Item Number identifying the pharmaceutical product at the trade item level. Encoded in the 2D DataMatrix barcode on the package. Used for product identification in DSCSA transaction data and EU FMD verification.. Valid values are `^[0-9]{14}$`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Date and time when this serialization record was most recently updated in the enterprise data platform. Tracks the latest status change, verification event, or ownership transfer recorded against this serialized unit.',
    `last_verification_timestamp` TIMESTAMP COMMENT 'Date and time of the most recent verification event performed against the medicines verification system (NMVS/EMVS). Used to track verification frequency and identify units that have not been recently verified.',
    `pack_size` STRING COMMENT 'Quantity and unit of the pharmaceutical product contained in the individual saleable unit (e.g., 30 tablets, 10 mL vial, 1 pre-filled syringe). Used for dispensing verification and supply chain planning.',
    `packaging_level` STRING COMMENT 'Level of the packaging hierarchy this serialization record represents. unit is the individual saleable unit (SGTIN); bundle is a multi-pack; case is a shipping case (SSCC); pallet is a pallet-level aggregation (SSCC). Drives aggregation hierarchy logic.. Valid values are `unit|bundle|case|pallet`',
    `parent_serial_number` STRING COMMENT 'Serial number of the immediate parent container in the aggregation hierarchy (e.g., the case serial number for a unit, or the pallet serial number for a case). Enables reconstruction of the full unit→case→pallet aggregation tree for DSCSA and EU FMD compliance.',
    `product_name` STRING COMMENT 'Commercial or brand name of the pharmaceutical product associated with this serialized unit. Included for operational readability and reporting without requiring a join to the product master.',
    `recall_flag` BOOLEAN COMMENT 'Indicates whether this serialized unit is subject to an active product recall. Set to TRUE when the units lot number is included in a recall notification. Enables rapid identification and quarantine of affected units across the supply chain.',
    `regulatory_market_code` STRING COMMENT 'Regulatory market authorization code or product registration number applicable to the market country. Links the serialized unit to the specific marketing authorization (NDA/BLA/MAA) under which it was released for that market.',
    `saleable_return_flag` BOOLEAN COMMENT 'Indicates whether this serialized unit has been returned from the market and assessed as eligible for re-entry into the saleable supply chain. Requires verification against the NMVS/EMVS and GDP assessment before re-release.',
    `serial_number` STRING COMMENT 'Unique alphanumeric serial number assigned to an individual saleable unit or case during commissioning. Conforms to GS1 SGTIN or SSCC encoding standards. Required for DSCSA unit-level traceability and EU FMD verification at point of dispense.',
    `serialization_status` STRING COMMENT 'Current lifecycle status of the serialized unit within the track-and-trace system. commissioned = activated at manufacturing; active = in supply chain; shipped = dispatched to trading partner; returned = returned from market; decommissioned = intentionally removed; destroyed = physically destroyed.. Valid values are `commissioned|active|shipped|returned|decommissioned|destroyed`',
    `source_system_code` STRING COMMENT 'Identifier of the originating serialization system or track-and-trace platform (e.g., SAP Advanced Track and Trace for Pharmaceuticals, Tracelink, Serialized Inventory Management System) that generated this record. Used for data lineage and system reconciliation.',
    `storage_condition` STRING COMMENT 'Required storage condition for the serialized unit as specified in the products approved labeling and stability data. Drives warehouse zone assignment, cold-chain logistics, and GDP compliance monitoring.. Valid values are `ambient|refrigerated|frozen|controlled_room_temp|protect_from_light`',
    `supply_chain_type` STRING COMMENT 'Indicates whether the serialized unit belongs to the commercial supply chain or the clinical trial supply chain. Clinical trial units require additional IND/CTA traceability. Compassionate use units require special regulatory tracking.. Valid values are `commercial|clinical_trial|sample|compassionate_use`',
    `transaction_statement_flag` BOOLEAN COMMENT 'Indicates whether a valid DSCSA Transaction Statement has been received and verified for this serialized unit from the upstream trading partner. Required under DSCSA Section 582 for each change of ownership in the pharmaceutical supply chain.',
    `verification_status` STRING COMMENT 'Result of the most recent verification check of the serialized unit against the national or European medicines verification system (NMVS/EMVS). verified = authentication passed; failed = authentication failed (potential falsification); pending = verification in progress; not_verified = not yet checked.. Valid values are `verified|failed|pending|not_verified`',
    CONSTRAINT pk_serialization_record PRIMARY KEY(`serialization_record_id`)
) COMMENT 'Unit-level and case-level serialization record for pharmaceutical finished goods compliant with DSCSA (Drug Supply Chain Security Act) and EU FMD (Falsified Medicines Directive) requirements. Captures serial number, GTIN, NDC, lot number, expiry date, aggregation hierarchy (unit→case→pallet), commissioning event, decommissioning event, verification status, and trading partner transaction history. Enables end-to-end track-and-trace across the pharmaceutical supply chain.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`supply`.`cold_chain_record` (
    `cold_chain_record_id` BIGINT COMMENT 'Unique identifier for the cold chain monitoring record. Primary key for the cold_chain_record product.',
    `brand_id` BIGINT COMMENT 'Foreign key linking to commercial.brand. Business justification: Cold chain excursions require brand-level disposition decisions and regulatory reporting. Commercial teams need brand-level cold chain deviation metrics for product quality KPIs and customer/regulator',
    `business_partner_id` BIGINT COMMENT 'Foreign key linking to masterdata.business_partner. Business justification: cold_chain_record.carrier_name is a denormalized plain-text field. Linking to masterdata.business_partner enables carrier qualification tracking, GDP deviation attribution to specific carriers, and ca',
    `distribution_network_id` BIGINT COMMENT 'Foreign key linking to supply.distribution_network. Business justification: cold_chain_record has location_code (string) and location_type identifying where the temperature reading was taken, but no FK to the distribution_network. Adding distribution_network_id → distribution',
    `drug_product_id` BIGINT COMMENT 'Foreign key linking to product.drug_product. Business justification: Temperature monitoring requirements and excursion thresholds are drug product-specific (formulation-dependent stability profiles). Product link required for deviation assessment, disposition decisions',
    `inventory_lot_id` BIGINT COMMENT 'Foreign key linking to supply.inventory_lot. Business justification: Cold chain monitoring records track temperature/humidity for specific inventory lots. The lot_number (STRING) should be replaced with inventory_lot_id FK to inventory_lot.inventory_lot_id. Material id',
    `investigational_product_id` BIGINT COMMENT 'Foreign key linking to clinical.investigational_product. Business justification: Cold-chain excursions affecting IMP shipments must be assessed against the specific investigational products stability profile for QP disposition decisions. GDP regulations require linking temperatur',
    `material_id` BIGINT COMMENT 'Foreign key linking to masterdata.material. Business justification: Temperature monitoring must reference material storage requirements (min/max thresholds, excursion tolerances) from material master. Essential for excursion assessment, disposition decisions, and GDP ',
    `preceding_cold_chain_record_id` BIGINT COMMENT 'Self-referencing FK on cold_chain_record (preceding_cold_chain_record_id)',
    `shipment_id` BIGINT COMMENT 'The unique identifier of the shipment or delivery if the monitoring occurred during transit. Links to shipment records for end-to-end traceability.',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to masterdata.storage_location. Business justification: Cold chain deviations occurring at a storage location must be linked to the validated storage zone for GDP deviation management, CAPA initiation, and re-qualification decisions. cold_chain_record.stor',
    `capa_reference` STRING COMMENT 'The reference number of the CAPA investigation initiated in response to the temperature excursion, if applicable.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this cold chain monitoring record was first created in the system. Used for audit trail and data lineage.',
    `deviation_reference` STRING COMMENT 'The reference number of the quality deviation or non-conformance record associated with the temperature excursion event.',
    `device_type` STRING COMMENT 'The category of temperature monitoring device used to capture the reading.. Valid values are `data_logger|wireless_sensor|usb_logger|bluetooth_tag|rfid_sensor|manual_thermometer`',
    `disposition_decision_date` DATE COMMENT 'The date when the quality disposition decision was made following excursion investigation and impact assessment.',
    `disposition_rationale` STRING COMMENT 'The documented justification and scientific rationale for the disposition decision, including stability data and risk assessment results.',
    `disposition_status` STRING COMMENT 'The quality disposition decision for the product following temperature monitoring or excursion investigation. Determines whether product can be released for use.. Valid values are `approved|quarantined|rejected|under_investigation|released`',
    `excursion_duration_minutes` STRING COMMENT 'The total duration in minutes that the temperature or humidity remained outside the acceptable range during the excursion event.',
    `excursion_end_timestamp` TIMESTAMP COMMENT 'The date and time when the temperature or humidity returned to within the acceptable range, marking the end of the excursion event.',
    `excursion_flag` BOOLEAN COMMENT 'Boolean indicator whether this reading represents a temperature or humidity excursion outside the acceptable range. True indicates an excursion event.',
    `excursion_severity` STRING COMMENT 'The severity classification of the temperature excursion based on the magnitude and duration of the deviation from acceptable range.. Valid values are `minor|moderate|major|critical`',
    `excursion_start_timestamp` TIMESTAMP COMMENT 'The date and time when the temperature or humidity first exceeded the acceptable threshold, marking the beginning of the excursion event.',
    `gdp_compliance_status` STRING COMMENT 'The assessment of whether the cold chain monitoring and handling met GDP requirements and regulatory standards.. Valid values are `compliant|non_compliant|under_review`',
    `humidity_reading_pct` DECIMAL(18,2) COMMENT 'The relative humidity percentage recorded by the monitoring device, if humidity monitoring is required for the product.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time when this cold chain monitoring record was most recently modified. Used for audit trail and change tracking.',
    `location_type` STRING COMMENT 'The category of location where the temperature monitoring occurred, indicating the supply chain segment.. Valid values are `warehouse|distribution_center|manufacturing_site|transit|clinical_site|pharmacy`',
    `monitoring_device_code` STRING COMMENT 'Unique identifier of the temperature monitoring device or data logger used to capture the reading. Required for device calibration traceability.',
    `monitoring_event_code` STRING COMMENT 'Business identifier for the temperature monitoring event or data collection session. Used for traceability and audit purposes.',
    `notes` STRING COMMENT 'Free-text field for additional comments, observations, or contextual information related to the temperature monitoring event or excursion.',
    `reading_timestamp` TIMESTAMP COMMENT 'The precise date and time when the temperature or humidity reading was captured by the monitoring device. Critical for excursion analysis.',
    `regulatory_report_date` DATE COMMENT 'The date when the temperature excursion event was reported to the relevant regulatory authority, if reporting was required.',
    `regulatory_reportable` BOOLEAN COMMENT 'Boolean indicator whether the temperature excursion event requires reporting to regulatory authorities such as FDA, EMA, or other health agencies.',
    `serial_number` STRING COMMENT 'Unique serialization identifier for the individual package or pallet being monitored, if serialization is implemented.',
    `storage_condition_required` STRING COMMENT 'The required storage condition classification for the pharmaceutical product as defined in the product specification and regulatory approval.. Valid values are `frozen|refrigerated|controlled_room_temperature|ambient`',
    `storage_zone` STRING COMMENT 'The specific storage zone, room, or area within the facility where the product was located during monitoring.',
    `supply_chain_segment` STRING COMMENT 'The segment of the pharmaceutical supply chain where the temperature monitoring occurred, enabling segment-specific analysis.. Valid values are `manufacturing|primary_distribution|secondary_distribution|last_mile|clinical_supply|reverse_logistics`',
    `temperature_max_threshold_c` DECIMAL(18,2) COMMENT 'The maximum acceptable temperature in degrees Celsius for the product storage condition. Readings above this trigger an excursion event.',
    `temperature_min_threshold_c` DECIMAL(18,2) COMMENT 'The minimum acceptable temperature in degrees Celsius for the product storage condition. Readings below this trigger an excursion event.',
    `temperature_reading_c` DECIMAL(18,2) COMMENT 'The actual temperature measurement in degrees Celsius recorded by the monitoring device at the reading timestamp.',
    `tracking_number` STRING COMMENT 'The carrier-assigned tracking number for the shipment, enabling correlation with carrier systems and proof of delivery.',
    CONSTRAINT pk_cold_chain_record PRIMARY KEY(`cold_chain_record_id`)
) COMMENT 'Transactional record capturing temperature monitoring data points and excursion events for cold-chain pharmaceutical products during storage and transit, including sensor readings, excursion duration, and disposition decisions';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`supply`.`recall_lot_scope` (
    `recall_lot_scope_id` BIGINT COMMENT 'Primary key for the recall_lot_scope association',
    `inventory_lot_id` BIGINT COMMENT 'Foreign key linking to the specific inventory lot included within the scope of this recall action.',
    `product_recall_id` BIGINT COMMENT 'Foreign key linking to the parent product recall event that initiated the scope of this lot inclusion.',
    `affected_quantity_per_lot` DECIMAL(18,2) COMMENT 'The quantity of this specific inventory lot that falls within the scope of the recall. Distinct from product_recall.quantity_distributed, which is the aggregate across all lots. Required for per-lot effectiveness check reporting to the FDA.',
    `disposition_per_lot` STRING COMMENT 'The approved disposition method for this specific lot as determined by quality review. May differ from the recall-level product_disposition on the parent recall record if lot-specific conditions (e.g., cold chain break, partial quantity) warrant a different disposition decision.',
    `notification_sent_flag` BOOLEAN COMMENT 'Indicates whether the holder or custodian of this specific inventory lot has been formally notified of the recall. Tracked per lot because lots may be held at different locations (3PL, distributor, hospital) requiring separate notification actions.',
    `recovery_date` DATE COMMENT 'The date on which this specific inventory lot was physically recovered, confirmed destroyed, or otherwise resolved within the recall process. Per-lot date required for FDA effectiveness check documentation.',
    `recovery_status` STRING COMMENT 'Current recovery status for this specific lot within the recall. Tracked independently per lot as different lots may be at different stages of recovery simultaneously. Cannot reside on inventory_lot (which reflects current inventory state) or product_recall (which is aggregate).',
    CONSTRAINT pk_recall_lot_scope PRIMARY KEY(`recall_lot_scope_id`)
) COMMENT 'This association product represents the operational scoping event between a product_recall and a specific inventory_lot in pharmaceutical recall management. It captures the per-lot tracking required by FDA 21 CFR Part 7 effectiveness checks, recording the affected quantity, recovery status, disposition method, and notification state for each individual lot included in a recall action. Each record links one product_recall to one inventory_lot and carries attributes that exist only in the context of that specific recall-lot pairing — they cannot reside on the recall header (which is aggregate) or the inventory lot (which reflects current inventory state).. Existence Justification: In pharmaceutical recall operations, a single recall event explicitly targets multiple specific inventory lots (e.g., all lots of NDC 12345-678-90 manufactured between Jan–Jun 2024), and a single inventory lot can be subject to multiple recalls across its lifecycle (e.g., a lot recalled for labeling deficiency and later for contamination). The FDAs recall effectiveness check process requires tracking each affected lot individually with its own recovery status, disposition, and notification record. This is an operationally managed relationship — recall coordinators actively create, update, and close records per lot — not an analytical derivation.';

